-- Schema for Domain: audience | Business:  | Version: v2_ecm
-- Generated on: 2026-06-30 04:18:25

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `vibe_media_broadcasting_v1`.`audience` COMMENT 'Owns audience measurement, ratings intelligence, and viewership data — Nielsen ratings, GRP/TRP/HUT/PUT metrics, sweeps period data, reach and frequency reporting, demographic segmentation, and engagement metrics. Integrates with Nielsen Media Research Platform and Adobe Experience Platform to provide the authoritative audience dataset for ad sales, programming decisions, and regulatory reporting.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`nielsen_rating` (
    `nielsen_rating_id` BIGINT COMMENT 'Unique surrogate identifier for each Nielsen audience measurement record in the Silver layer. Primary key for the nielsen_rating data product. | Column nielsen_rating_id (BIGINT) in audience.nielsen_rating',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Nielsen ratings must track originating broadcast facility for FCC regulatory compliance reporting, signal quality correlation analysis, and transmission verification. Broadcast facilities are the lice | Column broadcast_facility_id (BIGINT) in technology.nielsen_rating',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Ratings measurement tied to specific licensed broadcast facilities for regulatory reporting. Nielsen data aggregated by license for FCC public interest demonstration and license renewal applications. | Column broadcast_license_id (BIGINT) in compliance.nielsen_rating',
    `sales_campaign_id` BIGINT COMMENT 'Foreign key linking to sales.campaign. Business justification: Nielsen ratings measure campaign delivery performance for billing reconciliation, makegood determination, and audience guarantee compliance. Essential for post-campaign analysis and advertiser reporti | Column campaign_id (BIGINT) in sales.nielsen_rating',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or network on which the program aired and for which this rating was measured. | Column channel_id (BIGINT) in scheduling.nielsen_rating',
    `closed_caption_record_id` BIGINT COMMENT 'Foreign key linking to compliance.closed_caption_record. Business justification: Nielsen measurement includes closed captioning compliance verification for FCC reporting. Ratings data used to demonstrate accessibility compliance in public interest filings and license renewals. | Column closed_caption_record_id (BIGINT) in compliance.nielsen_rating',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Nielsen ratings measurement requires content rating context for demographic targeting compliance (COPPA childrens programming restrictions) and advertiser suitability verification. Essential for regu | Column compliance_content_rating_id (BIGINT) in compliance.nielsen_rating',
    `incident_id` BIGINT COMMENT 'Foreign key linking to compliance.incident. Business justification: Rating measurement failures or data breaches constitute compliance incidents requiring documentation. Links ratings data to incident records for root cause analysis and regulatory notification. | Column compliance_incident_id (BIGINT) in compliance.nielsen_rating',
    `daypart_id` BIGINT COMMENT 'Reference to the daypart (time segment of the broadcast day) during which the program aired, such as Prime Time, Late Night, or Early Morning. Daypart is a core dimension for ad sales and programming decisions. | Column daypart_id (BIGINT) in scheduling.nielsen_rating',
    `market_coverage_id` BIGINT COMMENT 'Reference to the geographic market (DMA or national) for which this rating measurement applies. Supports both national and local market measurement. | Column market_coverage_id (BIGINT) in audience.nielsen_rating',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each Nielsen rating uses a specific measurement methodology (PPM, diary, set-top box). The measurement_type string should be replaced with FK to measurement_methodology for MRC accreditation tracking  | Column measurement_methodology_id (BIGINT) in audience.nielsen_rating',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.nielsen_rating',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Nielsen ratings for syndicated content must track which distribution partners broadcast generated the rating for syndication performance reporting and partner revenue reconciliation. Essential for pa | Column partner_id (BIGINT) in partner.nielsen_rating',
    `political_ad_record_id` BIGINT COMMENT 'Foreign key linking to compliance.political_ad_record. Business justification: Nielsen ratings used for political advertising rate calculations (lowest unit charge) and public file disclosure. FCC requires ratings documentation for political ad pricing verification and equal tim | Column political_ad_record_id (BIGINT) in compliance.nielsen_rating',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level Nielsen ratings are the primary measurement unit for episodic television. Required for per-episode performance analysis, makegood calculations, and syndication valuation. Standard indust | Column production_episode_id (BIGINT) in production.nielsen_rating',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Nielsen ratings reports measure performance of specific production projects/series. Essential for greenlight decisions, talent negotiations, and advertiser delivery verification. Standard operational  | Column production_project_id (BIGINT) in production.nielsen_rating',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Ratings directly measure profit center performance for network/channel business units. Quarterly profit center reviews and segment reporting for investors require tying advertising revenue and audienc | Column profit_center_id (BIGINT) in finance.nielsen_rating',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Nielsen ratings data included in FCC filings for license renewal and public interest demonstration. Ratings evidence programming service to community and support renewal applications. | Column regulatory_filing_id (BIGINT) in compliance.nielsen_rating',
    `sox_control_id` BIGINT COMMENT 'Foreign key linking to compliance.sox_control. Business justification: Nielsen ratings data used in revenue recognition controls for SOX compliance (advertising revenue). Ratings support revenue assertions; links measurement data to financial reporting controls. | Column sox_control_id (BIGINT) in compliance.nielsen_rating',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Nielsen ratings during sweeps periods (Feb, May, July, Nov) are the currency for annual upfront negotiations and local ad sales. The sweeps_period_flag indicates relevance, but the specific sweeps per | Column sweeps_period_id (BIGINT) in audience.nielsen_rating',
    `title_id` BIGINT COMMENT 'Reference to the program entity for which this audience measurement record was captured. Links to the program master data product. | Column title_id (BIGINT) in content.nielsen_rating',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.nielsen_rating',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.nielsen_rating',
    `air_date` DATE COMMENT 'The calendar date on which the program episode aired on the specified channel and market. Used as the principal business event date for this measurement record. | Column air_date (DATE) in audience.nielsen_rating',
    `air_end_time` TIMESTAMP COMMENT 'The precise date and time at which the program finished airing. Combined with air_start_time to derive program duration for audience measurement calculations. | Column air_end_time (TIMESTAMP) in audience.nielsen_rating',
    `air_start_time` TIMESTAMP COMMENT 'The precise date and time (including timezone offset) at which the program began airing. Used for exact scheduling alignment and daypart classification. | Column air_start_time (TIMESTAMP) in audience.nielsen_rating',
    `audience_composition_pct` DECIMAL(18,2) COMMENT 'The percentage of the programs total audience represented by the primary target demographic (typically A18-49). Indicates how well the program indexes against its target audience and is used in ad sales proposals and programming strategy. | Column audience_composition_pct (DECIMAL(7,4)) in audience.nielsen_rating',
    `average_audience` DECIMAL(18,2) COMMENT 'The average number of persons or households tuned to the program during an average minute of the telecast. Expressed in thousands (000s). AA is the primary audience volume metric used in GRP and CPM calculations for ad sales. | Column average_audience (DECIMAL(14,2)) in audience.nielsen_rating',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.nielsen_rating',
    `cume_audience` DECIMAL(18,2) COMMENT 'The unduplicated number of different persons or households that tuned to the program for at least one minute across all airings within a defined period. Expressed in thousands (000s). Cume measures total reach and is critical for frequency management in ad campaign planning. | Column cume_audience (DECIMAL(14,2)) in audience.nielsen_rating',
    `demo_a18_49_rating` DECIMAL(18,2) COMMENT 'The percentage of Adults aged 18-49 in the measured universe who were tuned to this program. A18-49 is the most commercially valuable and widely traded demographic in US television advertising, serving as the primary currency for primetime ad sales. | Column demo_a18_49_rating (DECIMAL(7,4)) in audience.nielsen_rating',
    `demo_a25_54_rating` DECIMAL(18,2) COMMENT 'The percentage of Adults aged 25-54 in the measured universe who were tuned to this program. A25-54 is a key secondary demographic used in news programming, cable networks, and certain advertiser categories. | Column demo_a25_54_rating (DECIMAL(7,4)) in audience.nielsen_rating',
    `demo_k2_11_rating` DECIMAL(18,2) COMMENT 'The percentage of Children aged 2-11 in the measured universe who were tuned to this program. K2-11 is the primary demographic for childrens programming and toy/food advertisers. Subject to COPPA compliance requirements for data handling. | Column demo_k2_11_rating (DECIMAL(7,4)) in audience.nielsen_rating',
    `demo_m18_49_rating` DECIMAL(18,2) COMMENT 'The percentage of Men aged 18-49 in the measured universe who were tuned to this program. M18-49 is a primary demographic for sports, automotive, and technology advertisers. | Column demo_m18_49_rating (DECIMAL(7,4)) in audience.nielsen_rating',
    `demo_w18_49_rating` DECIMAL(18,2) COMMENT 'The percentage of Women aged 18-49 in the measured universe who were tuned to this program. W18-49 is a primary demographic for lifestyle, beauty, and household product advertisers. | Column demo_w18_49_rating (DECIMAL(7,4)) in audience.nielsen_rating',
    `frequency` DECIMAL(18,2) COMMENT 'The average number of times a unique person or household was exposed to the program within the measurement period. Frequency = GRP / Reach. Used with reach for ad campaign effectiveness analysis and makegoods calculations. | Column frequency (DECIMAL(7,2)) in audience.nielsen_rating',
    `grp` DECIMAL(18,2) COMMENT 'The sum of all ratings delivered by an advertising schedule or program, representing total audience delivery without deduplication. GRP = Reach × Frequency. A fundamental currency metric in ad sales negotiations, upfront deals, and scatter market transactions. | Column grp (DECIMAL(10,4)) in audience.nielsen_rating',
    `household_rating` DECIMAL(18,2) COMMENT 'The percentage of all television households in the measured universe that were tuned to this program during the measurement period. Expressed as a decimal percentage (e.g., 5.2 = 5.2%). The foundational Nielsen rating metric used for ad pricing and programming evaluation. | Column household_rating (DECIMAL(7,4)) in audience.nielsen_rating',
    `household_share` DECIMAL(18,2) COMMENT 'The percentage of households using television (HUT) that were tuned to this program. Share = (Program Audience / HUT) × 100. Measures competitive performance relative to active TV viewers at the same time. | Column household_share (DECIMAL(7,4)) in audience.nielsen_rating',
    `hut_level` DECIMAL(18,2) COMMENT 'The percentage of all television households in the universe that had their television sets in use during the measurement period. HUT is the denominator for household share calculations and a key indicator of overall TV viewing activity. | Column hut_level (DECIMAL(7,4)) in audience.nielsen_rating',
    `impressions` DECIMAL(18,2) COMMENT 'The total number of person-level exposures to the program, calculated as average audience multiplied by the number of airings. Expressed in absolute numbers (not thousands). Impressions are the transactional currency for digital and cross-platform ad sales. | Column impressions (DECIMAL(18,2)) in audience.nielsen_rating',
    `ingested_timestamp` TIMESTAMP COMMENT 'The timestamp at which this Nielsen rating record was ingested into the Databricks Lakehouse Silver layer from the Nielsen Media Research Platform. Used for data freshness monitoring, SLA tracking, and audit trail. | Column ingested_timestamp (TIMESTAMP) in audience.nielsen_rating',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent update to this rating record in the Silver layer, reflecting revisions from Nielsen (e.g., preliminary to final, or restated ratings). Supports change tracking and downstream consumer notification. | Column last_updated_timestamp (TIMESTAMP) in audience.nielsen_rating',
    `nielsen_program_code` STRING COMMENT 'Nielsen Media Research Platforms proprietary alphanumeric code uniquely identifying the program title within the Nielsen measurement system. Used as the business identifier for cross-referencing ratings data with Nielsen deliverables. | Column nielsen_program_code (STRING) in audience.nielsen_rating',
    `nielsen_report_date` DATE COMMENT 'The date on which Nielsen Media Research officially published or delivered this rating record to the broadcaster. Distinguishes the measurement air date from the data delivery date, which is critical for tracking preliminary vs. final rating release cycles. | Column nielsen_report_date (DATE) in audience.nielsen_rating',
    `nielsen_report_week` STRING COMMENT 'The ISO 8601 week identifier (e.g., 2024-W23) of the Nielsen measurement week in which this rating was reported. Nielsen measurement weeks run Monday through Sunday. Used for weekly ratings aggregation and trend analysis. | Column nielsen_report_week (STRING) in audience.nielsen_rating. Valid values are `^d{4}-W(0[1-9]|[1-4][0-9]|5[0-3])$`',
    `put_level` DECIMAL(18,2) COMMENT 'The percentage of all persons in the measured universe who were watching television during the measurement period. PUT is the denominator for persons share calculations and complements HUT for demographic audience analysis. | Column put_level (DECIMAL(7,4)) in audience.nielsen_rating',
    `rating_status` STRING COMMENT 'Lifecycle status of this Nielsen rating record indicating whether the data is preliminary (fast nationals), final, or has been revised. Ad sales and programming decisions must distinguish preliminary from final ratings. Preliminary ratings are typically released within 24 hours; final ratings follow within days. | Column rating_status (STRING) in audience.nielsen_rating. Valid values are `preliminary|final|revised|estimated|withheld`',
    `reach` DECIMAL(18,2) COMMENT 'The unduplicated number of unique persons or households exposed to the program at least once within the measurement period. Expressed in thousands (000s). Reach is a core metric for ad campaign planning and audience delivery reporting. | Column reach (DECIMAL(14,2)) in audience.nielsen_rating',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.nielsen_rating',
    `source_system_record_code` STRING COMMENT 'The native record identifier assigned by the Nielsen Media Research Platform for this rating record. Preserved in the Silver layer for data lineage, reconciliation, and re-ingestion traceability back to the authoritative source system. | Column source_system_record_code (STRING) in audience.nielsen_rating',
    `sweeps_period_flag` BOOLEAN COMMENT 'Indicates whether this rating was measured during a Nielsen Sweeps period (February, May, July, November intensive measurement periods). Sweeps ratings carry elevated importance for affiliate compensation, ad rate setting, and programming strategy. | Column sweeps_period_flag (BOOLEAN) in audience.nielsen_rating',
    `time_spent_viewing_min` DECIMAL(18,2) COMMENT 'The average number of minutes that viewers in the measured audience spent watching the program. A key engagement metric used in programming decisions and content performance analysis. Expressed in minutes. | Column time_spent_viewing_min (DECIMAL(10,2)) in audience.nielsen_rating',
    `total_audience` DECIMAL(18,2) COMMENT 'The total number of persons or households that tuned to the program for at least six consecutive minutes. Expressed in thousands (000s). TA provides a broader reach measure than AA and is used for program promotion and scheduling decisions. | Column total_audience (DECIMAL(14,2)) in audience.nielsen_rating',
    `trp` DECIMAL(18,2) COMMENT 'Rating points delivered specifically to a defined target demographic audience (e.g., Adults 18-49). TRP = (Target Audience Impressions / Target Universe) × 100. Used by advertisers to evaluate efficiency of reaching their specific target demographic. | Column trp (DECIMAL(10,4)) in audience.nielsen_rating',
    `universe_estimate_hh` DECIMAL(18,2) COMMENT 'The total estimated number of television households in the measured market or national universe used as the denominator for household rating calculations. Expressed in thousands (000s). Nielsen updates universe estimates annually based on census data. | Column universe_estimate_hh (DECIMAL(14,2)) in audience.nielsen_rating',
    `universe_estimate_persons` DECIMAL(18,2) COMMENT 'The total estimated number of persons in the measured market or national universe used as the denominator for persons rating calculations. Expressed in thousands (000s). Segmented by demographic group for TRP calculations. | Column universe_estimate_persons (DECIMAL(14,2)) in audience.nielsen_rating',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.nielsen_rating',
    CONSTRAINT pk_nielsen_rating PRIMARY KEY(`nielsen_rating_id`)
) COMMENT 'Authoritative audience measurement record capturing program-level ratings data including household rating, share, HUT/PUT levels, GRP, TRP, average audience (AA), total audience (TA), cume audience, and demographic breakdowns (A18-49, A25-54, W18-49, M18-49, K2-11, etc.) for a specific program airing on a specific channel, market, and daypart. Sourced from Nielsen Media Research Platform. Includes universe estimates used as denominators for percentage calculations. The SSOT for all ratings intelligence consumed by ad sales, programming, and regulatory reporting. Supports both national and local market measurement. | Unity Catalog table: media_broadcasting_ecm.audience.nielsen_rating Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`demographic_segment` (
    `demographic_segment_id` BIGINT COMMENT 'Unique surrogate identifier for each demographic segment record in the audience measurement reference master. Primary key for the demographic_segment product. [_canonical_skip_reason: Role classified as REFERENCE_LOOKUP — this is a reference master for standardized audience demographic classification cells; per-role minimums are exempt, but MASTER_RESOURCE minimums are applied given the entity carries rich descriptive and lifecycle attributes beyond a simple code list.] | Column demographic_segment_id (BIGINT) in audience.demographic_segment',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.demographic_segment',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.demographic_segment',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.demographic_segment',
    `adobe_segment_code` STRING COMMENT 'The corresponding segment identifier in Adobe Experience Platform (AEP) for digital audience activation. Enables cross-system reconciliation between Nielsen linear audience measurement and AEP digital audience profiles for cross-platform campaign targeting and DAI (Dynamic Ad Insertion) on OTT/streaming platforms. | Column adobe_segment_code (STRING) in audience.demographic_segment',
    `age_range_max` STRING COMMENT 'Upper bound (inclusive) of the age range defining this demographic cell, expressed in years. For example, 49 for the A18-49 cell. A null value indicates an open-ended upper bound (e.g., Adults 55+). Null for non-age-based segments. | Column age_range_max (INT) in audience.demographic_segment',
    `age_range_min` STRING COMMENT 'Lower bound (inclusive) of the age range defining this demographic cell, expressed in years. For example, 18 for the A18-49 cell. Null for non-age-based segments such as psychographic or income quintile segments. | Column age_range_min (INT) in audience.demographic_segment',
    `cpm_index` DECIMAL(18,2) COMMENT 'Relative CPM (Cost Per Mille) pricing index for this demographic segment compared to the baseline segment (index = 100). Premium segments such as A18-49 or W25-54 carry higher indices reflecting advertiser demand. Used in Salesforce Media Cloud ad sales proposals and upfront/scatter market pricing negotiations. Confidential commercial pricing data. | Column cpm_index (DECIMAL(10,4)) in audience.demographic_segment',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.demographic_segment',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this demographic segment record was first created in the Silver Layer data product. Provides audit trail for data governance and lineage tracking in the Databricks Lakehouse environment. | Column created_timestamp (TIMESTAMP) in audience.demographic_segment',
    `daypart_relevance` STRING COMMENT 'Comma-separated list of broadcast dayparts (e.g., Prime Time, Late Fringe, Daytime) for which this demographic segment has primary relevance in programming and ad sales strategy. Informs Ericsson MediaFirst scheduling decisions and Wide Orbit daypart-based ad pod targeting. Null if the segment applies across all dayparts. | Column daypart_relevance (STRING) in audience.demographic_segment',
    `effective_from` DATE COMMENT 'The date from which this demographic segment definition is valid and available for use in audience measurement, ad sales targeting, and programming decisions. Supports temporal versioning of segment definitions as Nielsen and IAB standards evolve. | Column effective_from (DATE) in audience.demographic_segment',
    `effective_until` DATE COMMENT 'The date after which this demographic segment definition is no longer valid for new audience measurement or ad targeting use. Null for currently active segments with no planned expiry. Enables historical ratings data to reference the correct segment definition vintage. | Column effective_until (DATE) in audience.demographic_segment',
    `ethnicity_classification` STRING COMMENT 'Standardized ethnicity classification label for ethnicity-based demographic segments (e.g., Hispanic/Latino, African American, Asian American, Non-Hispanic White). Populated only for ethnicity segment types. Aligned with Nielsen multicultural audience measurement standards and used in targeted content programming and ad sales. [ENUM-REF-CANDIDATE: hispanic_latino|african_american|asian_american|non_hispanic_white|native_american|multiracial|other — promote to reference product] | Column ethnicity_classification (STRING) in audience.demographic_segment',
    `gdpr_special_category` BOOLEAN COMMENT 'Indicates whether this demographic segment is based on GDPR Article 9 special category data (e.g., ethnicity, health status). When true, enhanced consent and data processing controls are required for EU audience data associated with this segment. Relevant for pan-European distribution platforms and Ofcom-regulated services. | Column gdpr_special_category (BOOLEAN) in audience.demographic_segment',
    `gender_qualifier` STRING COMMENT 'Gender dimension of the demographic cell. All denotes combined-gender segments (e.g., Adults 18-49, Persons 2+). Aligns with Nielsen standard gender breakdowns used in GRP/TRP calculations and ad sales targeting. | Column gender_qualifier (STRING) in audience.demographic_segment. Valid values are `all|male|female|non_binary`',
    `geographic_scope` STRING COMMENT 'The geographic level at which this demographic segment definition is applied. National segments are used for network-level ratings and upfront sales; DMA (Designated Market Area) segments apply to local market measurement; local applies to individual station markets; international for global distribution platforms. | Column geographic_scope (STRING) in audience.demographic_segment. Valid values are `national|dma|local|international`',
    `grp_weight_factor` DECIMAL(18,2) COMMENT 'Weighting factor applied to this demographic segment when calculating Gross Rating Points (GRP) and Target Rating Points (TRP) in audience measurement reports. Reflects the relative population size and measurement panel representation of the segment. Sourced from the Nielsen Media Research Platform and used in Wide Orbit ad scheduling and campaign delivery calculations. | Column grp_weight_factor (DECIMAL(10,6)) in audience.demographic_segment',
    `household_composition` STRING COMMENT 'Classification of household structure for household-based demographic segments. Used in HUT (Homes Using Television) and PUT (Persons Using Television) audience measurement reporting and in family-oriented programming and advertising targeting strategies. | Column household_composition (STRING) in audience.demographic_segment. Valid values are `single|couple_no_children|family_with_children|empty_nester|multigenerational`',
    `iab_audience_code` STRING COMMENT 'The IAB Audience Taxonomy 2.0 standardized code corresponding to this demographic segment. Enables cross-platform audience targeting alignment between linear broadcast, OTT/AVOD/SVOD digital campaigns, and programmatic advertising systems. Used in Salesforce Media Cloud ad proposals and Adobe Experience Platform segment mapping. | Column iab_audience_code (STRING) in audience.demographic_segment',
    `income_quintile` STRING COMMENT 'Household income quintile ranking (1=lowest 20%, 5=highest 20%) for income-based demographic segments. Populated only for income quintile segment types. Used in premium CPM pricing tiers and upfront ad sales targeting for high-value audience packages. | Column income_quintile (INT) in audience.demographic_segment',
    `is_children_segment` BOOLEAN COMMENT 'Indicates whether this demographic segment includes individuals under 13 years of age (e.g., K2-11, K2-5). Triggers COPPA compliance controls on data collection, ad targeting restrictions, and content rating enforcement. Critical for regulatory compliance in digital and broadcast advertising. | Column is_children_segment (BOOLEAN) in audience.demographic_segment',
    `is_key_demo` BOOLEAN COMMENT 'Flags whether this segment is designated as a key demographic (key demo) for the organizations primary ad sales and programming strategy. Key demos (typically A18-49, W25-54) command premium CPM rates and are the primary currency in upfront and scatter market negotiations. | Column is_key_demo (BOOLEAN) in audience.demographic_segment',
    `is_nielsen_standard_cell` BOOLEAN COMMENT 'Indicates whether this demographic segment corresponds to an official Nielsen standard demographic cell (e.g., A18-49, W25-54). True for Nielsen-defined cells used in GRP/TRP/HUT/PUT ratings calculations; False for custom or proprietary segments defined internally or via Adobe Experience Platform. | Column is_nielsen_standard_cell (BOOLEAN) in audience.demographic_segment',
    `measurement_methodology` STRING COMMENT 'The audience measurement methodology used to quantify this demographic segment. Panel-based measurement uses Nielsen People Meter panels; census-based uses set-top box or streaming data; hybrid combines both; modeled uses statistical projection. Determines data quality, confidence intervals, and applicability for regulatory reporting. | Column measurement_methodology (STRING) in audience.demographic_segment. Valid values are `panel|census|hybrid|modeled`',
    `nielsen_cell_label` STRING COMMENT 'The exact Nielsen Media Research standard cell label for this demographic segment (e.g., A18-49, W25-54, M18-34, K2-11, P2+). Used as the authoritative cross-reference when ingesting Nielsen ratings data and reconciling audience measurement reports from the Nielsen Media Research Platform. | Column nielsen_cell_label (STRING) in audience.demographic_segment',
    `nielsen_segment_code` STRING COMMENT 'The native segment identifier assigned by the Nielsen Media Research Platform for this demographic cell. Used for direct API integration with Nielsen ratings data feeds, ensuring accurate mapping of audience measurement data to internal segment definitions. | Column nielsen_segment_code (STRING) in audience.demographic_segment',
    `platform_applicability` STRING COMMENT 'Indicates the distribution platforms for which this demographic segment definition is applicable. Linear segments apply to traditional broadcast/cable measurement; digital applies to OTT/streaming (SVOD, AVOD, FAST); cross-platform spans both; all applies universally. Drives segment availability in Wide Orbit (linear) vs. Adobe Experience Platform (digital) targeting. | Column platform_applicability (STRING) in audience.demographic_segment. Valid values are `linear|digital|cross_platform|all`',
    `psychographic_profile` STRING COMMENT 'Descriptive label for psychographic segment classification (e.g., Early Adopters, Value Seekers, Sports Enthusiasts, News Junkies). Populated only for psychographic segment types. Derived from Adobe Experience Platform audience profiling and used in premium ad sales targeting and programming strategy. | Column psychographic_profile (STRING) in audience.demographic_segment',
    `reach_potential_pct` DECIMAL(18,2) COMMENT 'Estimated maximum reach potential expressed as a percentage of the segment universe achievable across the organizations full distribution footprint. Used in media planning to set realistic reach targets for ad campaigns and programming strategies. Sourced from Nielsen reach and frequency models. | Column reach_potential_pct (DECIMAL(5,2)) in audience.demographic_segment',
    `regulatory_restriction_flag` BOOLEAN COMMENT 'Indicates whether this demographic segment is subject to regulatory restrictions on data collection, targeting, or advertising. True for segments including minors (COPPA), sensitive demographic categories under GDPR Article 9, or segments subject to FCC advertising restrictions. Triggers compliance workflow in Adobe Experience Platform and Wide Orbit. | Column regulatory_restriction_flag (BOOLEAN) in audience.demographic_segment',
    `segment_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the demographic segment, aligned with Nielsen and IAB standard cell codes (e.g., A18-49, W25-54, M18-34, K2-11, P2+). Used as the business-facing identifier in ad sales proposals, ratings reports, and audience targeting systems. | Column segment_code (STRING) in audience.demographic_segment. Valid values are `^[A-Z0-9]{2,20}$`',
    `segment_description` STRING COMMENT 'Full narrative description of the demographic segments defining characteristics, measurement criteria, and intended use cases. Provides context for business users in ad sales, programming, and analytics teams on how to correctly apply and interpret the segment in audience measurement and targeting workflows. | Column segment_description (STRING) in audience.demographic_segment',
    `segment_name` STRING COMMENT 'Human-readable label for the demographic segment (e.g., Adults 18-49, Women 25-54, Men 18-34, Kids 2-11). Used in reporting dashboards, ad sales presentations, and EPG audience targeting configurations. | Column segment_name (STRING) in audience.demographic_segment',
    `segment_status` STRING COMMENT 'Current lifecycle state of the demographic segment definition. Active segments are available for audience targeting, ad sales proposals, and ratings reporting. Deprecated segments are retained for historical continuity but no longer used in new campaigns or programming decisions. | Column segment_status (STRING) in audience.demographic_segment. Valid values are `active|inactive|deprecated|pending_review`',
    `segment_type` STRING COMMENT 'Classification of the segment by its primary defining dimension. Distinguishes age/gender cells (Nielsen standard cells such as A18-49) from psychographic profiles, income quintiles, ethnicity classifications, behavioral clusters, and household composition segments. Drives which measurement methodology and data source applies. | Column segment_type (STRING) in audience.demographic_segment. Valid values are `age_gender|psychographic|income|ethnicity|behavioral|household`',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.demographic_segment',
    `sweeps_priority` BOOLEAN COMMENT 'Indicates whether this demographic segment is a priority measurement target during Nielsen sweeps periods (February, May, July, November). Priority segments receive enhanced panel measurement and are the primary basis for affiliate compensation and ad rate card negotiations during sweeps. | Column sweeps_priority (BOOLEAN) in audience.demographic_segment',
    `universe_estimate` BIGINT COMMENT 'Total estimated population count (universe) for this demographic segment in the measurement geography, as defined by Nielsen. Used as the denominator in ratings calculations (rating = audience / universe × 100). Updated periodically from Nielsen universe estimates and used in GRP, TRP, reach, and frequency reporting. | Column universe_estimate (BIGINT) in audience.demographic_segment',
    `universe_estimate_year` STRING COMMENT 'The calendar year for which the universe estimate is valid. Nielsen updates universe estimates annually; this field identifies the vintage of the estimate to ensure correct ratings calculations and year-over-year audience trend analysis. | Column universe_estimate_year (INT) in audience.demographic_segment',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.demographic_segment',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this demographic segment record was most recently modified. Used for incremental data pipeline processing, change data capture, and audit compliance in the Databricks Lakehouse Silver Layer. | Column updated_timestamp (TIMESTAMP) in audience.demographic_segment',
    CONSTRAINT pk_demographic_segment PRIMARY KEY(`demographic_segment_id`)
) COMMENT 'Reference master for standardized audience demographic segments used across Nielsen ratings, ad sales, and programming decisions. Defines age/gender cells (A18-49, W25-54, M18-34, K2-11, etc.), psychographic segments, income quintiles, and ethnicity classifications aligned with Nielsen and IAB standards. Used as the authoritative classification for all audience targeting and measurement reporting. | Unity Catalog table: media_broadcasting_ecm.audience.demographic_segment Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`sweeps_period` (
    `sweeps_period_id` BIGINT COMMENT 'Unique surrogate identifier for each Nielsen sweeps measurement period record in the Media Broadcasting audience data product. | Column sweeps_period_id (BIGINT) in audience.sweeps_period',
    `calendar_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_calendar. Business justification: Sweeps periods drive compliance calendar deadlines for ratings-based regulatory filings. FCC public file updates and license renewal exhibits tied to sweeps completion dates. | Column calendar_id (BIGINT) in compliance.sweeps_period',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each sweeps period uses a specific measurement methodology (PPM, diary, or hybrid). The measurement_methodology string should be replaced with FK to measurement_methodology master for consistency and  | Column measurement_methodology_id (BIGINT) in audience.sweeps_period',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.sweeps_period',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Sweeps period results required in regulatory filings for performance documentation. FCC license renewals and ownership transfer applications reference sweeps ratings as public interest evidence. | Column regulatory_filing_id (BIGINT) in compliance.sweeps_period',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.sweeps_period',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.sweeps_period',
    `audience_sample_size` STRING COMMENT 'Total number of Nielsen panel respondents (diary participants or PPM device carriers) included in the measurement sample for this sweeps period. Larger sample sizes yield higher statistical confidence in ratings estimates. | Column audience_sample_size (INT) in audience.sweeps_period',
    `blackout_markets` STRING COMMENT 'Comma-separated list of DMA market codes where geographic broadcast blackout restrictions apply during this sweeps period. Blackout markets are excluded from certain ratings calculations and ad delivery reporting per FCC and contractual requirements. | Column blackout_markets (STRING) in audience.sweeps_period',
    `ccpa_applicable` BOOLEAN COMMENT 'Indicates whether CCPA viewer data privacy requirements apply to the measurement data collected during this sweeps period (e.g., for California DMA markets in scope). Governs opt-out rights and data sale restrictions for audience panel data. | Column ccpa_applicable (BOOLEAN) in audience.sweeps_period',
    `coppa_applicable` BOOLEAN COMMENT 'Indicates whether COPPA restrictions apply to audience data collected during this sweeps period, specifically for childrens programming dayparts or platforms. Governs collection and use of audience data for viewers under 13. | Column coppa_applicable (BOOLEAN) in audience.sweeps_period',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.sweeps_period',
    `data_release_status` STRING COMMENT 'Indicates the current release state of Nielsen audience data for this sweeps period. unreleased = data not yet available; preliminary = fast affiliate estimates published; final = confirmed ratings delivered; revised_final = post-delivery corrections applied. | Column data_release_status (STRING) in audience.sweeps_period. Valid values are `unreleased|preliminary|final|revised_final`',
    `daypart_coverage` STRING COMMENT 'Indicates which dayparts (time segments of the broadcast day) are included in the sweeps measurement scope. all_dayparts covers the full broadcast day; other values indicate restricted measurement windows. Daypart coverage affects which ad inventory can be rated and guaranteed. | Column daypart_coverage (STRING) in audience.sweeps_period. Valid values are `all_dayparts|primetime_only|primetime_and_late_news|custom`',
    `demographic_breakdowns` STRING COMMENT 'Comma-separated list of demographic segments for which Nielsen will provide audience measurement data during this sweeps period (e.g., A18-49,A25-54,W18-34,M18-49,HH). Determines which target audience guarantees can be supported for ad sales. | Column demographic_breakdowns (STRING) in audience.sweeps_period',
    `diary_return_rate_pct` DECIMAL(18,2) COMMENT 'For diary-methodology sweeps periods, the percentage of distributed Nielsen viewing diaries that were returned by respondents. A key data quality indicator; low return rates may trigger Nielsen data quality warnings or adjustments. | Column diary_return_rate_pct (DECIMAL(5,2)) in audience.sweeps_period',
    `dma_list_version` STRING COMMENT 'Version identifier of the Nielsen DMA market list applied during this sweeps period (e.g., DMA-2024-v1). Nielsen periodically revises DMA boundaries; this field ensures correct market mapping for historical comparisons. | Column dma_list_version (STRING) in audience.sweeps_period',
    `duration_days` STRING COMMENT 'Total number of calendar days in the sweeps measurement window (end_date minus start_date inclusive). Typically 28 days for standard Nielsen sweeps periods. Used in pacing and audience guarantee calculations. | Column duration_days (INT) in audience.sweeps_period',
    `end_date` DATE COMMENT 'The official last day of the Nielsen sweeps measurement window as defined by Nielsen Media Research. Audience data collection and ratings calculations conclude on this date. | Column end_date (DATE) in audience.sweeps_period',
    `gdpr_applicable` BOOLEAN COMMENT 'Indicates whether GDPR audience data privacy requirements apply to the measurement data collected during this sweeps period (e.g., for EU markets included in scope). Governs data retention, consent, and anonymization obligations for audience panel data. | Column gdpr_applicable (BOOLEAN) in audience.sweeps_period',
    `grp_guarantee_applicable` BOOLEAN COMMENT 'Indicates whether Gross Rating Point (GRP) audience guarantees negotiated during the upfront or scatter market apply to advertising campaigns running within this sweeps period. True = GRP guarantees in effect; False = no guarantees applicable. | Column grp_guarantee_applicable (BOOLEAN) in audience.sweeps_period',
    `hut_measurement_included` BOOLEAN COMMENT 'Indicates whether Homes Using Television (HUT) level data is captured and reported as part of this sweeps period measurement. HUT data is used to calculate share and contextualize ratings within total available audience. | Column hut_measurement_included (BOOLEAN) in audience.sweeps_period',
    `is_special_programming_flag` BOOLEAN COMMENT 'Indicates whether special programming (e.g., season premieres, finales, major sporting events, stunting) was scheduled during this sweeps period that may inflate or distort ratings relative to non-sweeps periods. True = special programming present; False = standard schedule. | Column is_special_programming_flag (BOOLEAN) in audience.sweeps_period',
    `makegood_window_end_date` DATE COMMENT 'The last date by which makegoods (compensatory ad spots issued when audience guarantees are not met) must be aired following this sweeps period. Defined in advertiser contracts and governed by Wide Orbit traffic system scheduling. | Column makegood_window_end_date (DATE) in audience.sweeps_period',
    `market_count` STRING COMMENT 'Total number of Designated Market Areas (DMAs) included in this sweeps measurement period. Used to assess geographic coverage and local affiliate reporting obligations. | Column market_count (INT) in audience.sweeps_period',
    `market_scope` STRING COMMENT 'Indicates whether this sweeps period covers national audience measurement, local market (DMA) measurement, or both. Determines which ad sales rate cards and audience guarantees apply. | Column market_scope (STRING) in audience.sweeps_period. Valid values are `national|local|both`',
    `nielsen_contract_ref` STRING COMMENT 'Reference number of the Nielsen Media Research contract or service agreement under which this sweeps period measurement is conducted. Used for billing reconciliation and SLA enforcement with Nielsen. | Column nielsen_contract_ref (STRING) in audience.sweeps_period',
    `nielsen_sweep_code` STRING COMMENT 'The externally-assigned Nielsen Media Research Platform identifier for this sweeps period (e.g., SWEEP-2024-NOV). Used to cross-reference records with Nielsen source data and reconcile audience measurement deliverables. | Column nielsen_sweep_code (STRING) in audience.sweeps_period',
    `period_status` STRING COMMENT 'Current lifecycle state of the sweeps period record. scheduled = future period confirmed by Nielsen; active = measurement currently in progress; completed = measurement concluded and data delivered; cancelled = period cancelled (rare); revised = dates or scope amended post-publication. | Column period_status (STRING) in audience.sweeps_period. Valid values are `scheduled|active|completed|cancelled|revised`',
    `ppm_compliance_rate_pct` DECIMAL(18,2) COMMENT 'For PPM-methodology sweeps periods, the percentage of PPM panel members who met Nielsens minimum daily wear-time compliance threshold. Low compliance rates may affect the statistical validity of ratings data. | Column ppm_compliance_rate_pct (DECIMAL(5,2)) in audience.sweeps_period',
    `preliminary_ratings_date` DATE COMMENT 'The date on which Nielsen delivers preliminary (fast affiliate) ratings estimates for this sweeps period. Preliminary data is used for early ad sales negotiations before final ratings are confirmed. | Column preliminary_ratings_date (DATE) in audience.sweeps_period',
    `put_measurement_included` BOOLEAN COMMENT 'Indicates whether Persons Using Television (PUT) level data is captured and reported as part of this sweeps period measurement. PUT data enables person-level demographic audience analysis beyond household-level HUT data. | Column put_measurement_included (BOOLEAN) in audience.sweeps_period',
    `ratings_delivery_date` DATE COMMENT 'The date on which Nielsen is contractually obligated to deliver final audience ratings data for this sweeps period to the broadcaster. Drives downstream ad sales billing, makegoods calculations, and audience guarantee reconciliation. | Column ratings_delivery_date (DATE) in audience.sweeps_period',
    `record_created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this sweeps period record was first created in the Media Broadcasting Databricks Silver layer data product. Supports audit trail and data lineage tracking. | Column record_created_timestamp (TIMESTAMP) in audience.sweeps_period',
    `record_updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this sweeps period record was most recently modified in the Media Broadcasting Databricks Silver layer data product. Used for change tracking, SLA monitoring, and downstream refresh orchestration. | Column record_updated_timestamp (TIMESTAMP) in audience.sweeps_period',
    `regulatory_reporting_required` BOOLEAN COMMENT 'Indicates whether audience measurement data from this sweeps period must be submitted to a regulatory body (e.g., FCC, Ofcom) as part of broadcast licensing compliance or public interest reporting obligations. | Column regulatory_reporting_required (BOOLEAN) in audience.sweeps_period',
    `source_last_updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which the source system (Nielsen Media Research Platform) last updated the record for this sweeps period. Used for incremental data ingestion and change detection in the Databricks Silver layer pipeline. | Column source_last_updated_timestamp (TIMESTAMP) in audience.sweeps_period',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.sweeps_period',
    `start_date` DATE COMMENT 'The official first day of the Nielsen sweeps measurement window as defined by Nielsen Media Research. Audience data collection and ratings calculations begin on this date. | Column start_date (DATE) in audience.sweeps_period',
    `stunting_description` STRING COMMENT 'Free-text description of any programming stunts or special events scheduled during this sweeps period (e.g., Season finale of flagship drama, Super Bowl lead-out programming). Populated only when is_special_programming_flag is True. | Column stunting_description (STRING) in audience.sweeps_period',
    `sweep_month` STRING COMMENT 'The calendar month in which the sweeps measurement period falls. Nielsen conducts four sweeps periods annually: February, May, July, and November. Drives programming strategy and ad rate negotiations. | Column sweep_month (STRING) in audience.sweeps_period. Valid values are `February|May|July|November`',
    `sweep_name` STRING COMMENT 'Human-readable label for the sweeps period (e.g., November 2024 Sweeps, February 2025 Sweeps). Used in reports, ad sales proposals, and programming strategy documents. | Column sweep_name (STRING) in audience.sweeps_period',
    `sweep_year` STRING COMMENT 'The four-digit calendar year in which the sweeps measurement period occurs (e.g., 2024). Used to uniquely identify the period in combination with sweep_month. | Column sweep_year (INT) in audience.sweeps_period',
    `trp_guarantee_applicable` BOOLEAN COMMENT 'Indicates whether Target Rating Point (TRP) audience guarantees for specific demographic targets apply to advertising campaigns running within this sweeps period. True = TRP guarantees in effect; False = no TRP guarantees applicable. | Column trp_guarantee_applicable (BOOLEAN) in audience.sweeps_period',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.sweeps_period',
    `upfront_rate_card_applicable` BOOLEAN COMMENT 'Indicates whether advertising rates negotiated during the upfront sales event apply to inventory sold within this sweeps period. True = upfront rate cards govern pricing; False = scatter market rates apply. | Column upfront_rate_card_applicable (BOOLEAN) in audience.sweeps_period',
    CONSTRAINT pk_sweeps_period PRIMARY KEY(`sweeps_period_id`)
) COMMENT 'Master record for each Nielsen sweeps measurement period (February, May, July, November) defining the official start and end dates, measurement methodology (diary vs. PPM), markets in scope, and special programming flags. Sweeps periods drive programming strategy, ad rate negotiations, and audience guarantee calculations. Sourced from Nielsen Media Research Platform. | Unity Catalog table: media_broadcasting_ecm.audience.sweeps_period Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`panel` (
    `panel_id` BIGINT COMMENT 'Unique surrogate identifier for the audience measurement panel record in the lakehouse. Primary key for the audience_panel entity. | Column panel_id (BIGINT) in audience.panel',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Audience panels require dedicated panel managers responsible for recruitment, retention, weighting methodology compliance, and MRC accreditation maintenance. Manager assignment critical for universe e | Column manager_employee_id (BIGINT) in workforce.panel',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Audience panels are defined for specific DMAs/markets. The dma_code and dma_name are redundant with market_coverage master data. Normalizing ensures consistency with market definitions used across nie | Column market_coverage_id (BIGINT) in audience.panel',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Each panel uses a specific measurement methodology (PPM, diary, set-top box). The measurement_provider string should be replaced with FK to measurement_methodology for consistency. Panel-specific impl | Column measurement_methodology_id (BIGINT) in audience.panel',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.panel',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.panel',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.panel',
    `adobe_segment_code` STRING COMMENT 'Identifier linking this audience panel definition to a corresponding audience segment or profile group in Adobe Experience Platform (AEP). Enables cross-platform audience activation by mapping Nielsen panel demographics to digital audience segments for personalization and targeted ad delivery. | Column adobe_segment_code (STRING) in audience.panel',
    `panel_code` STRING COMMENT 'Externally-known alphanumeric code assigned by the measurement provider (e.g., Nielsen) to uniquely identify this panel within their system. Used for cross-system reconciliation with the Nielsen Media Research Platform. | Column panel_code (STRING) in audience.panel. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `cooperation_rate` DECIMAL(18,2) COMMENT 'Percentage of recruited panel households or individuals who are actively and consistently providing usable measurement data. A declining cooperation rate is an early indicator of panel quality degradation and may trigger MRC review. Expressed as a decimal (e.g., 0.8500 = 85%). | Column cooperation_rate (DECIMAL(6,4)) in audience.panel',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code indicating the primary country of coverage for this panel (e.g., USA, GBR, AUS). Required for international panels and regulatory reporting to Ofcom and the European Audiovisual Observatory. | Column country_code (STRING) in audience.panel. Valid values are `^[A-Z]{3}$`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.panel',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience panel record was first created in the lakehouse Silver layer. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for data lineage, audit trails, and compliance with SOX financial reporting controls that require traceability of audience data used in revenue recognition. | Column created_timestamp (TIMESTAMP) in audience.panel',
    `data_collection_method` STRING COMMENT 'Technical mechanism used to collect viewing data from panel members. Electronic meters (people meters) require active button-pressing; set-top-box (STB) and smart TV ACR (Automatic Content Recognition) are passive; diary is self-reported. Determines the granularity and reliability of minute-by-minute audience data. | Column data_collection_method (STRING) in audience.panel. Valid values are `electronic_meter|portable_meter|set_top_box|smart_tv_acr|diary|hybrid`',
    `demographic_composition` STRING COMMENT 'Narrative or structured description of the demographic breakdowns captured by this panel (e.g., Age 2+, Adults 18-49, Adults 25-54, Persons 2-17, Households by income quintile). Defines which demographic cuts are available for TRP (Target Rating Point) calculations and demographic audience guarantees in ad sales. | Column demographic_composition (STRING) in audience.panel',
    `effective_end_date` DATE COMMENT 'Date on which this panel was retired or superseded by a newer panel vintage. Null for currently active panels. Used to scope historical ratings queries to the correct panel vintage and to manage panel transitions during sweeps periods. | Column effective_end_date (DATE) in audience.panel',
    `effective_start_date` DATE COMMENT 'Date on which this panel became the active currency measurement source for audience projections. Marks the beginning of the period for which this panels data is used in ratings reports, ad sales guarantees, and GRP/TRP delivery calculations. | Column effective_start_date (DATE) in audience.panel',
    `geographic_scope` STRING COMMENT 'Breadth of geographic coverage represented by this panel. National panels project to the total US population; DMA (Designated Market Area) panels project to a specific local television market; International panels cover non-US territories. | Column geographic_scope (STRING) in audience.panel. Valid values are `national|dma|local_market|regional|international`',
    `measurement_currency_flag` BOOLEAN COMMENT 'Indicates whether this panel is designated as the official currency measurement source for audience guarantees in advertising transactions. True = this panels data is used as the contractual basis for GRP/TRP delivery and makegood calculations in upfront and scatter market deals. False = supplemental or research-only panel. | Column measurement_currency_flag (BOOLEAN) in audience.panel',
    `min_reportable_rating` DECIMAL(18,2) COMMENT 'The lowest audience rating value (expressed as a decimal fraction of the universe) that this panel can reliably report without exceeding acceptable statistical error thresholds. Ratings below this threshold are suppressed or flagged as unreliable. Typically expressed as a percentage (e.g., 0.0010 = 0.1%). Governed by MRC minimum cell size requirements. | Column min_reportable_rating (DECIMAL(6,4)) in audience.panel',
    `mrc_accreditation_date` DATE COMMENT 'Date on which the MRC most recently granted or renewed accreditation for this panel. Used to track accreditation currency and schedule renewal audits. Panels must maintain continuous accreditation to support upfront and scatter market ad sales guarantees. | Column mrc_accreditation_date (DATE) in audience.panel',
    `mrc_accreditation_expiry_date` DATE COMMENT 'Date on which the current MRC accreditation for this panel expires and must be renewed. Expiry triggers a mandatory re-audit process. Ad sales teams must be notified of impending expiry to manage risk on guaranteed audience delivery commitments. | Column mrc_accreditation_expiry_date (DATE) in audience.panel',
    `mrc_accreditation_status` STRING COMMENT 'Current accreditation status granted by the Media Rating Council (MRC) for this panel. MRC accreditation is the industry standard for currency-grade audience measurement. Accredited panels are required for guaranteed ad buys and upfront sales commitments. Non-accredited panels cannot be used as primary currency. | Column mrc_accreditation_status (STRING) in audience.panel. Valid values are `accredited|conditionally_accredited|not_accredited|under_review|suspended`',
    `panel_name` STRING COMMENT 'Human-readable name of the audience measurement panel (e.g., Nielsen National People Meter 2024, Nielsen Local People Meter — New York DMA). Used in reporting, dashboards, and ad sales presentations. | Column panel_name (STRING) in audience.panel',
    `nielsen_panel_code` STRING COMMENT 'Nielsens proprietary internal identifier for this panel as maintained in the Nielsen Media Research Platform. Used for direct API integration, data feed reconciliation, and cross-referencing Nielsen ratings reports. Distinct from the internal audience_panel_id surrogate key. | Column nielsen_panel_code (STRING) in audience.panel. Valid values are `^[A-Z0-9]{6,20}$`',
    `notes` STRING COMMENT 'Free-text field for capturing operational notes, known data quality issues, methodology changes, or special considerations associated with this panel (e.g., Sample boosted in Q3 2023 for Hispanic demographic, Methodology change effective Jan 2024 — includes streaming). Used by audience analytics and ad sales teams. | Column notes (STRING) in audience.panel',
    `out_of_home_measurement_flag` BOOLEAN COMMENT 'Indicates whether this panel captures out-of-home (OOH) viewing, such as viewing in bars, hotels, airports, and other public venues. OOH measurement is captured via Portable People Meter (PPM) technology. OOH-inclusive panels produce higher total audience estimates than in-home-only panels. | Column out_of_home_measurement_flag (BOOLEAN) in audience.panel',
    `panel_status` STRING COMMENT 'Current lifecycle state of the audience panel. Active panels are used for currency-grade audience projections. Suspended panels are temporarily halted due to quality or compliance issues. Retired panels are decommissioned and replaced by newer vintages. | Column panel_status (STRING) in audience.panel. Valid values are `active|inactive|suspended|retired|pending_accreditation`',
    `panel_type` STRING COMMENT 'Classification of the audience measurement methodology used by this panel. National People Meter (NPM) and Local People Meter (LPM) are electronic metered panels; Portable People Meter (PPM) captures out-of-home exposure; Diary is self-reported; Return Path Data (RPD) is set-top-box passback data; Hybrid combines multiple methods. | Column panel_type (STRING) in audience.panel. Valid values are `national_people_meter|local_people_meter|portable_people_meter|diary|return_path_data|hybrid`',
    `recruitment_methodology` STRING COMMENT 'Statistical sampling approach used to recruit panel members. Probability-based sampling (address-based or random-digit-dial) is required for MRC-accredited currency panels. Opt-in panels are used for supplemental or proprietary measurement. Affects the projectability and accreditation status of the panel. | Column recruitment_methodology (STRING) in audience.panel. Valid values are `probability_sample|address_based|random_digit_dial|opt_in_panel|hybrid`',
    `refresh_frequency` STRING COMMENT 'Cadence at which panel membership is rotated or refreshed to prevent panel conditioning effects and maintain demographic representativeness. Annual and biennial refreshes are standard for people meter panels; continuous recruitment is used for large-scale return path data panels. | Column refresh_frequency (STRING) in audience.panel. Valid values are `annual|biennial|continuous|on_demand`',
    `reporting_granularity` STRING COMMENT 'Finest time interval at which this panel can produce reliable audience estimates. Minute-by-minute granularity is available from electronic people meter panels and supports DAI (Dynamic Ad Insertion) optimization. Quarter-hour is standard for diary panels. Determines compatibility with EPG-based program-level ratings reporting. | Column reporting_granularity (STRING) in audience.panel. Valid values are `minute|quarter_hour|program|daypart|daily`',
    `sampling_error_pct` DECIMAL(18,2) COMMENT 'Estimated margin of error (as a percentage) for audience projections derived from this panel at a 95% confidence interval. Smaller panels have higher sampling error. Used by ad sales teams to communicate measurement uncertainty to advertisers and to set makegood thresholds for audience delivery shortfalls. | Column sampling_error_pct (DECIMAL(6,4)) in audience.panel',
    `size_households` STRING COMMENT 'Total number of sample households actively participating in this panel at any given time. Drives the statistical reliability and margin of error of projected audience estimates. A larger panel size yields lower sampling error for low-rated programs. | Column size_households (INT) in audience.panel',
    `size_individuals` STRING COMMENT 'Total number of individual persons (panelists) actively measured within this panel. Distinct from household count because multiple individuals per household are measured for demographic breakdowns used in Target Rating Point (TRP) calculations. | Column size_individuals (INT) in audience.panel',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.panel',
    `streaming_measurement_flag` BOOLEAN COMMENT 'Indicates whether this panel captures streaming and OTT (Over-The-Top) viewing in addition to linear broadcast. Streaming-enabled panels support cross-platform audience measurement combining linear TV, SVOD, AVOD, and FAST channel viewing for total audience reporting. | Column streaming_measurement_flag (BOOLEAN) in audience.panel',
    `sweeps_eligible_flag` BOOLEAN COMMENT 'Indicates whether this panel is used during Nielsen Sweeps periods (February, May, July, November) for local market ratings measurement. Sweeps data drives local ad rates and program scheduling decisions. Only MRC-accredited panels with sufficient local market sample sizes are sweeps-eligible. | Column sweeps_eligible_flag (BOOLEAN) in audience.panel',
    `universe_estimate` BIGINT COMMENT 'Total projected population size (in persons or households) that this panel is designed to represent. The universe estimate is the denominator used to convert raw panel viewing counts into ratings percentages (e.g., HUT, PUT, Share). Updated periodically based on census data. | Column universe_estimate (BIGINT) in audience.panel',
    `universe_estimate_type` STRING COMMENT 'Specifies whether the universe_estimate represents total households, total persons, or TV households (HUT-eligible). TV households are the standard denominator for HUT (Homes Using Television) calculations in broadcast ratings. | Column universe_estimate_type (STRING) in audience.panel. Valid values are `households|persons|tv_households`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.panel',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience panel record was most recently modified in the lakehouse Silver layer. Follows ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used to detect stale panel configurations and trigger downstream recalculation of audience projections dependent on this panel. | Column updated_timestamp (TIMESTAMP) in audience.panel',
    `vintage_year` STRING COMMENT 'Calendar year in which this panel sample was designed and recruited. Panels are periodically refreshed to maintain demographic representativeness as the population changes. Vintage year is used to track panel age and schedule mandatory refreshes per MRC accreditation requirements. | Column vintage_year (INT) in audience.panel',
    `weighting_factor` DECIMAL(18,2) COMMENT 'Numeric multiplier applied to this panels raw viewing data to project sample observations to the total universe estimate. A weighting factor greater than 1.0 indicates the panel under-represents a demographic segment relative to the population. Used in GRP and TRP calculations. | Column weighting_factor (DECIMAL(10,6)) in audience.panel',
    `weighting_methodology` STRING COMMENT 'Description of the statistical weighting approach applied to panel data to correct for demographic imbalances and non-response bias (e.g., Iterative Proportional Fitting / Raking, Post-stratification weighting by age/sex/race/income). Critical for ensuring projected audience estimates are representative of the total population. | Column weighting_methodology (STRING) in audience.panel',
    CONSTRAINT pk_panel PRIMARY KEY(`panel_id`)
) COMMENT 'Master record representing a Nielsen or proprietary audience measurement panel — a statistically representative sample of households or individuals used to project viewership to the total population. Captures panel type (Nielsen National People Meter, Nielsen Local People Meter, PPM, Diary, Return Path Data), panel size, geographic coverage (national or DMA-specific), demographic composition, panel vintage, recruitment methodology, weighting factors, and MRC accreditation status. Foundation for all projected audience estimates and the basis for measurement credibility. | Unity Catalog table: media_broadcasting_ecm.audience.panel Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`viewership_record` (
    `viewership_record_id` BIGINT COMMENT 'Unique surrogate identifier for each granular viewership record in the Silver Layer lakehouse. Primary key for this entity. | Column viewership_record_id (BIGINT) in audience.viewership_record',
    `sales_campaign_id` BIGINT COMMENT 'Foreign key linking to sales.campaign. Business justification: Viewership records are attributed to campaigns for cross-platform measurement, addressable advertising delivery verification, and DAI performance tracking. Essential for programmatic ad insertion and  | Column campaign_id (BIGINT) in sales.viewership_record',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or streaming platform channel on which the content was delivered. Used for channel-level ratings aggregation, share calculations, and carriage fee reporting. | Column channel_id (BIGINT) in scheduling.viewership_record',
    `compliance_consent_record_id` BIGINT COMMENT 'Foreign key linking to compliance.consent_record. Business justification: Viewership data collection requires active consent record for GDPR/CCPA compliance. Direct regulatory link ensuring data processing legality and supporting privacy request fulfillment (access, deletio | Column compliance_consent_record_id (BIGINT) in compliance.viewership_record',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Viewership tracking must enforce age-appropriate content delivery based on rating system for parental controls and COPPA compliance. Core requirement for subscriber protection and regulatory adherence | Column compliance_content_rating_id (BIGINT) in compliance.viewership_record',
    `incident_id` BIGINT COMMENT 'Foreign key linking to compliance.incident. Business justification: Viewership data breaches or unauthorized access trigger privacy compliance incidents. GDPR/CCPA breach notification requirements mandate linking affected records to incident documentation. | Column compliance_incident_id (BIGINT) in compliance.viewership_record',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Viewership data attributes content consumption to producing cost centers for ROI analysis. Content performance reports by cost center drive budget allocation and greenlight decisions for programming d | Column cost_center_id (BIGINT) in finance.viewership_record',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Viewership records undergo quality audits for billing reconciliation, ratings certification, and advertiser makegood disputes. Auditor assignment tracked for compliance trails, client dispute resoluti | Column data_quality_auditor_employee_id (BIGINT) in workforce.viewership_record',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Viewership records are classified by demographic segment for aggregation into Nielsen ratings. The demographic_age_band and demographic_gender should be replaced with FK to demographic_segment for con | Column demographic_segment_id (BIGINT) in audience.viewership_record',
    `device_type_id` BIGINT COMMENT 'Hashed device identifier (e.g., hashed advertising ID, set-top box serial hash, or streaming device fingerprint) from which the viewing session originated. Pseudonymized to prevent direct device tracking per GDPR and CCPA. Used for device-level reach and frequency analysis. | Column device_type_id (BIGINT) in distribution.viewership_record',
    `household_id` BIGINT COMMENT 'Hashed/anonymized identifier representing the household unit from which the viewing event originated, derived from set-top box or ACR data. Pseudonymized per GDPR Article 25 and CCPA Section 1798.100 to prevent direct re-identification. Used for Nielsen household-level ratings aggregation and HUT (Homes Using Television) calculations. | Column household_id (BIGINT) in subscriber.viewership_record',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Viewership records are tracked by DMA for local market measurement. The geographic_dma_code should be replaced with FK to market_coverage for consistency with nielsen_rating and other measurement prod | Column market_coverage_id (BIGINT) in audience.viewership_record',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.viewership_record',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Viewership data drives opportunity identification and sizing in ad sales. Sales teams analyze viewing patterns to identify high-value prospects and tailor pitches. Links actual audience behavior to sa | Column opportunity_id (BIGINT) in sales.viewership_record',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Viewership records require originating facility tracking for CDN routing optimization, regional blackout enforcement, local ad insertion decisioning, and FCC local content compliance. Role prefix dist | Column originating_broadcast_facility_id (BIGINT) in technology.viewership_record',
    `playback_session_id` BIGINT COMMENT 'External business identifier for the viewing session as assigned by the source system (Adobe Experience Platform, set-top box telemetry, or streaming platform). Used to correlate records across ingestion pipelines and deduplicate events from multiple sources. | Column session_id (STRING) in distribution.viewership_record',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level viewership tracking is standard for streaming platforms. Required for completion rate analysis, binge-watching pattern detection, and dynamic ad insertion targeting. Core operational lin | Column production_episode_id (BIGINT) in production.viewership_record',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Streaming viewership records must link to production projects for rights reporting, content performance dashboards, and recommendation algorithm training. Essential for VOD/SVOD platform operations an | Column production_project_id (BIGINT) in production.viewership_record',
    `schedule_slot_id` BIGINT COMMENT 'Reference to the specific scheduled airing or playout event from the Electronic Program Guide (EPG) that the viewer tuned into. Links to the program schedule managed in Ericsson MediaFirst. Null for on-demand (VOD/SVOD) sessions. | Column schedule_slot_id (BIGINT) in scheduling.viewership_record',
    `subscriber_id` BIGINT COMMENT 'Reference to the authenticated subscriber account from Zuora subscription billing, populated for SVOD and authenticated AVOD sessions. Null for anonymous linear broadcast or unauthenticated OTT viewing. | Column subscriber_id (BIGINT) in subscriber.viewership_record',
    `title_id` BIGINT COMMENT 'Reference to the content asset being viewed, linking to the content master catalog. Enables join to content metadata including title, genre, production details, and rights windows. | Column title_id (BIGINT) in content.viewership_record',
    `viewer_profile_id` BIGINT COMMENT 'Hashed/anonymized identifier representing an individual viewer within a household, derived from Adobe Experience Platform profile resolution or subscriber login. Pseudonymized per GDPR and CCPA. Used for PUT (Persons Using Television) and individual-level demographic analytics. | Column viewer_profile_id (BIGINT) in subscriber.viewership_record',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.viewership_record',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.viewership_record',
    `acr_source` STRING COMMENT 'The data collection methodology or source system that generated this viewership record. ACR = Automatic Content Recognition from smart TV; set_top_box = return-path data from cable/satellite STB; streaming_telemetry = OTT platform event stream via Adobe Experience Platform; panel = Nielsen People Meter panel; return_path = MVPD return-path data. | Column acr_source (STRING) in audience.viewership_record. Valid values are `set_top_box|acr|streaming_telemetry|panel|return_path`',
    `ad_break_count` STRING COMMENT 'Number of ad breaks (ad pods) encountered by the viewer during this viewing session. Used for DAI (Dynamic Ad Insertion) reconciliation, Wide Orbit affidavit verification, and advertiser delivery reporting. | Column ad_break_count (INT) in audience.viewership_record',
    `ads_viewed_count` STRING COMMENT 'Total number of individual advertisement spots viewed (not skipped) by the viewer during this session. Used for AVOD monetization reporting, CPM impression counting, and advertiser campaign delivery verification against Wide Orbit schedules. | Column ads_viewed_count (INT) in audience.viewership_record',
    `audience_share` DECIMAL(18,2) COMMENT 'The percentage of HUT (Homes Using Television) or PUT (Persons Using Television) tuned to this channel/program at the time of viewing, as reported by Nielsen. Share differs from rating in that it measures the proportion of active viewers rather than the total universe. Used for competitive programming analysis. | Column audience_share (DECIMAL(6,4)) in audience.viewership_record',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a geographic blackout restriction was applied to this viewing session, preventing delivery of specific content in the viewers DMA or region per rights agreements. Used for blackout compliance auditing and retransmission consent reporting. | Column blackout_applied (BOOLEAN) in audience.viewership_record',
    `broadcast_date` DATE COMMENT 'The calendar date (yyyy-MM-dd) of the broadcast or streaming session, in the local broadcast timezone. Used as the primary date dimension for daily ratings aggregation, sweeps period attribution, and Nielsen overnight ratings reporting. | Column broadcast_date (DATE) in audience.viewership_record',
    `cdn_edge_node` STRING COMMENT 'Identifier of the Akamai CDN edge node or point-of-presence (PoP) that served the streaming content for this session. Used for CDN performance analysis, SLA compliance monitoring, and geographic delivery optimization. | Column cdn_edge_node (STRING) in audience.viewership_record',
    `completion_rate` DECIMAL(18,2) COMMENT 'Proportion of the content asset viewed during this session, expressed as a decimal between 0.0000 and 1.0000 (e.g., 0.7500 = 75% viewed). Sourced directly from platform telemetry; not derived within this product. Used for engagement scoring, programming decisions, and advertiser reporting. | Column completion_rate (DECIMAL(5,4)) in audience.viewership_record',
    `content_duration_seconds` STRING COMMENT 'Total runtime in seconds of the full content asset or scheduled airing being viewed. Used as the denominator for completion rate calculations and to determine whether a full viewing occurred. | Column content_duration_seconds (INT) in audience.viewership_record',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the viewers geographic location at time of viewing. Used for international rights windowing compliance, GDPR/CCPA jurisdictional determination, and Ofcom/FCC regulatory reporting. | Column country_code (STRING) in audience.viewership_record. Valid values are `^[A-Z]{3}$`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.viewership_record',
    `data_source_system` STRING COMMENT 'Identifies the operational system of record from which this viewership record was ingested into the Silver Layer. Used for data lineage tracking, quality auditing, and source-system reconciliation. | Column data_source_system (STRING) in audience.viewership_record. Valid values are `adobe_experience_platform|nielsen_platform|akamai_cdn|set_top_box|acr_provider`',
    `daypart` STRING COMMENT 'The broadcast daypart time segment during which the tune-in occurred, as defined by industry standard time blocks. Daypart is a fundamental dimension for advertising sales (CPM pricing, GRP/TRP calculations), programming strategy, and Nielsen ratings reporting. [ENUM-REF-CANDIDATE: early_morning|daytime|early_fringe|prime_access|primetime|late_news|late_fringe|overnight — promote to reference product] | Column daypart (STRING) in audience.viewership_record',
    `delivery_type` STRING COMMENT 'Classification of how the content was delivered to the viewer. Linear = traditional scheduled broadcast; VOD = on-demand; SVOD = subscription on-demand; AVOD = ad-supported on-demand; TVOD = transactional/pay-per-view; FAST = Free Ad-Supported Streaming Television; Simulcast = simultaneous multi-platform broadcast. Critical for rights windowing compliance and revenue attribution. [ENUM-REF-CANDIDATE: linear|vod|svod|avod|tvod|fast|simulcast — 7 candidates stripped; promote to reference product] | Column delivery_type (STRING) in audience.viewership_record',
    `device_type` STRING COMMENT 'Category of device used to consume the content. Used for device-level audience segmentation, ad targeting eligibility, and platform-specific reach reporting. [ENUM-REF-CANDIDATE: tv|set_top_box|mobile|tablet|desktop|smart_tv|streaming_stick|gaming_console|dvr — promote to reference product] | Column device_type (STRING) in audience.viewership_record',
    `drm_protected` BOOLEAN COMMENT 'Indicates whether the content stream was delivered with DRM (Digital Rights Management) encryption active during this session. Used for rights compliance auditing, anti-piracy reporting to MPA, and content protection SLA verification. | Column drm_protected (BOOLEAN) in audience.viewership_record',
    `duration_viewed_seconds` STRING COMMENT 'Total number of seconds the viewer actively watched the content during this session, as reported by the source telemetry system. Accounts for pauses and buffering exclusions per platform telemetry rules. Used for TSR (Time Spent Reading/Viewing) calculations and completion rate derivation. | Column duration_viewed_seconds (INT) in audience.viewership_record',
    `ingestion_timestamp` TIMESTAMP COMMENT 'The date and time when this viewership record was first loaded into the Databricks Silver Layer lakehouse. Used for data freshness monitoring, SLA compliance, and audit trail purposes. Distinct from tune_in_timestamp (business event time). | Column ingestion_timestamp (TIMESTAMP) in audience.viewership_record',
    `is_authenticated` BOOLEAN COMMENT 'Indicates whether the viewer was authenticated (logged in) at the time of viewing. Authenticated sessions enable individual-level audience measurement and subscriber-linked analytics. Unauthenticated sessions rely on household or device-level inference. | Column is_authenticated (BOOLEAN) in audience.viewership_record',
    `is_sweeps_period` BOOLEAN COMMENT 'Flag indicating whether this viewership record falls within a Nielsen sweeps measurement period (February, May, July, November). Sweeps data is used for setting advertising rates and programming decisions. Critical for isolating sweeps vs. non-sweeps audience behavior. | Column is_sweeps_period (BOOLEAN) in audience.viewership_record',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this viewership record was last modified in the Silver Layer, for example due to late-arriving data corrections, Nielsen restatement, or session completion updates. Used for incremental processing and audit trail. | Column last_updated_timestamp (TIMESTAMP) in audience.viewership_record',
    `nielsen_program_rating` DECIMAL(18,2) COMMENT 'The Nielsen audience rating score associated with the program airing for this viewership record, representing the percentage of the total TV households or persons in the universe tuned to the program. Sourced from Nielsen Media Research Platform integration. Used for GRP/TRP calculations and ad rate setting. | Column nielsen_program_rating (DECIMAL(6,4)) in audience.viewership_record',
    `platform_type` STRING COMMENT 'The distribution platform category through which the content was delivered. Used for multi-platform audience aggregation, MVPD/vMVPD carriage reporting, and OTT vs. linear audience segmentation. [ENUM-REF-CANDIDATE: broadcast|cable|satellite|ott|mvpd|vmvpd|web|mobile|podcast|social — promote to reference product] | Column platform_type (STRING) in audience.viewership_record',
    `playback_position_seconds` STRING COMMENT 'The content offset position in seconds at which the viewer stopped watching (tune-out position within the asset). For linear broadcast, this reflects the offset from the scheduled start of the program. Used for resume-point analytics and mid-roll ad delivery attribution. | Column playback_position_seconds (INT) in audience.viewership_record',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.viewership_record',
    `stream_quality` STRING COMMENT 'The video quality level at which the content was delivered during this session, as reported by the ABR (Adaptive Bitrate Streaming) player or CDN telemetry from Akamai. Used for quality-of-experience reporting, CDN SLA compliance, and premium content delivery analytics. | Column stream_quality (STRING) in audience.viewership_record. Valid values are `4k_uhd|hd_1080|hd_720|sd|audio_only`',
    `tune_in_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) when the viewer began watching the content or tuned to the channel. This is the principal business event timestamp for the viewership record. Used for daypart analysis, time-spent calculations, and sweeps period attribution. | Column tune_in_timestamp (TIMESTAMP) in audience.viewership_record',
    `tune_out_timestamp` TIMESTAMP COMMENT 'The precise date and time (ISO 8601 with timezone offset) when the viewer stopped watching, changed channel, or the session ended. Used in conjunction with tune_in_timestamp to calculate duration_viewed_seconds. | Column tune_out_timestamp (TIMESTAMP) in audience.viewership_record',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.viewership_record',
    `viewing_status` STRING COMMENT 'Current lifecycle status of the viewing session record. completed = viewer watched to end or tune-out cleanly; in_progress = session still active at ingestion time; abandoned = viewer left before 10% completion; interrupted = session ended due to technical failure; error = telemetry data quality issue flagged. | Column viewing_status (STRING) in audience.viewership_record. Valid values are `completed|in_progress|abandoned|interrupted|error`',
    CONSTRAINT pk_viewership_record PRIMARY KEY(`viewership_record_id`)
) COMMENT 'Granular transactional record of audience viewing activity for a specific content airing or stream session, capturing tuning start/end timestamps, channel or platform, device type, household or individual viewer identifier (anonymized/hashed per GDPR/CCPA), duration viewed, and completion rate. Aggregated from set-top box data, ACR (Automatic Content Recognition), and streaming platform telemetry via Adobe Experience Platform integration. | Unity Catalog table: media_broadcasting_ecm.audience.viewership_record Nielsen measurement integration supported.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`reach_frequency_report` (
    `reach_frequency_report_id` BIGINT COMMENT 'Unique surrogate identifier for each reach and frequency report record in the Silver Layer lakehouse. Primary key for this transactional entity. | Column reach_frequency_report_id (BIGINT) in audience.reach_frequency_report',
    `advertiser_id` BIGINT COMMENT 'Foreign key linking to sales.advertiser. Business justification: Reach/frequency reports are generated for specific advertisers to show campaign performance across their portfolio, including cross-campaign reach, frequency distribution, and GRP/TRP delivery. Essent | Column advertiser_id (BIGINT) in sales.reach_frequency_report',
    `sales_campaign_id` BIGINT COMMENT 'Reference to the advertising campaign for which this reach and frequency report was produced. Links to the campaign master record in Salesforce Media Cloud. Used for post-campaign delivery validation and upfront guarantee reconciliation. | Column campaign_id (BIGINT) in sales.reach_frequency_report',
    `channel_id` BIGINT COMMENT 'Foreign key linking to scheduling.channel. Business justification: Reach/frequency reports are generated for specific networks/channels to measure campaign delivery by channel. Direct channel link enables automated report generation, channel-specific reach analysis,  | Column channel_id (BIGINT) in scheduling.reach_frequency_report',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Reach/frequency reports measure advertising campaign effectiveness by sales team cost center. Sales commission calculations and territory performance analysis require linking campaign delivery metrics | Column cost_center_id (BIGINT) in finance.reach_frequency_report',
    `daypart_id` BIGINT COMMENT 'Reference to the daypart (time segment of the broadcast day) for which audience measurement was computed. Links to the daypart reference product. Used to segment reach and frequency metrics by time-of-day for programming and ad sales analysis. | Column daypart_id (BIGINT) in scheduling.reach_frequency_report',
    `demographic_segment_id` BIGINT COMMENT 'Reference to the demographic segment (e.g., Adults 18-49, Women 25-54) against which reach and frequency metrics are measured. Links to the demographic segment reference product sourced from Nielsen Media Research Platform. Central to Target Rating Point (TRP) calculations and ad sales guarantees. | Column demographic_segment_id (BIGINT) in audience.reach_frequency_report',
    `market_coverage_id` BIGINT COMMENT 'Reference to the geographic market (DMA, national, or international market) for which this reach and frequency report applies. Links to the market reference product. Used for blackout compliance, scatter market pricing, and geographic audience analysis. | Column market_coverage_id (BIGINT) in audience.reach_frequency_report',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Reach/frequency reports are generated using specific Nielsen methodologies. The nielsen_methodology string should be replaced with FK to measurement_methodology for consistency and MRC accreditation t | Column measurement_methodology_id (BIGINT) in audience.reach_frequency_report',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.reach_frequency_report',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Reach/frequency reports are core deliverables in ad sales proposals and post-campaign analysis. Each R&F report is generated for a specific sales opportunity to demonstrate projected or actual campaig | Column opportunity_id (BIGINT) in sales.reach_frequency_report',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Reach/frequency reports are often generated for specific distribution or syndication partners to demonstrate audience delivery against contractual obligations. Required for partner performance reporti | Column partner_id (BIGINT) in partner.reach_frequency_report',
    `political_ad_record_id` BIGINT COMMENT 'Foreign key linking to compliance.political_ad_record. Business justification: Reach/frequency reports for political campaigns require public inspection file linkage per FCC rules. Demonstrates delivery of reasonable access and documents audience delivery for political advertise | Column political_ad_record_id (BIGINT) in compliance.reach_frequency_report',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Reach/frequency reports require certified analysts to validate GRP/TRP calculations, effective reach thresholds, and makegood determinations for advertiser guarantees. Analyst assignment tracked for c | Column report_analyst_employee_id (BIGINT) in workforce.reach_frequency_report',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Reach/frequency reports during sweeps periods are used for guarantee verification and makegood calculations. The is_sweeps_period flag indicates relevance, but the specific sweeps period should be ref | Column sweeps_period_id (BIGINT) in audience.reach_frequency_report',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.reach_frequency_report',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.reach_frequency_report',
    `audience_share_pct` DECIMAL(18,2) COMMENT 'The percentage of the total viewing audience (persons using television) that was watching the specific network or program during the measurement period. Calculated as the programs audience divided by the total HUT/PUT audience. Used for competitive programming analysis and ad sales positioning. | Column audience_share_pct (DECIMAL(7,4)) in audience.reach_frequency_report',
    `average_frequency` DECIMAL(18,2) COMMENT 'The average number of times a unique viewer within the target demographic was exposed to the content or campaign during the measurement period. Calculated as total impressions divided by unduplicated reach. Core metric for evaluating campaign saturation and makegoods calculation. | Column average_frequency (DECIMAL(8,4)) in audience.reach_frequency_report',
    `cpm` DECIMAL(18,2) COMMENT 'The cost per one thousand audience impressions for the campaign or programming block, expressed in USD. Used by ad sales for post-campaign delivery validation, scatter market pricing justification, and makegood valuation. Confidential as it reflects negotiated commercial pricing. | Column cpm (DECIMAL(10,4)) in audience.reach_frequency_report',
    `cprp` DECIMAL(18,2) COMMENT 'The cost per one rating point delivered against the target demographic segment, expressed in USD. The primary pricing metric for linear TV advertising transactions. Used for upfront guarantee reconciliation, makegood valuation, and scatter market pricing. Confidential as it reflects negotiated commercial pricing. | Column cprp (DECIMAL(10,4)) in audience.reach_frequency_report',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.reach_frequency_report',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this reach and frequency report record was first ingested into the Silver Layer lakehouse. Used for data lineage tracking and pipeline monitoring. | Column created_timestamp (TIMESTAMP) in audience.reach_frequency_report',
    `currency_code` STRING COMMENT 'The ISO 4217 three-letter currency code for all monetary values in this report (CPM, CPRP). Defaults to USD for domestic US markets. Required for international market reports and multi-currency financial reconciliation under SOX compliance. | Column currency_code (STRING) in audience.reach_frequency_report. Valid values are `^[A-Z]{3}$`',
    `delivery_variance_pct` DECIMAL(18,2) COMMENT 'The percentage difference between the guaranteed audience delivery (GRP or TRP) and the actual delivered audience for the campaign flight. A negative value indicates under-delivery triggering makegood obligations; a positive value indicates over-delivery. Used for upfront guarantee reconciliation and scatter market adjustments. | Column delivery_variance_pct (DECIMAL(7,4)) in audience.reach_frequency_report',
    `effective_reach_1plus` BIGINT COMMENT 'The count of unique persons exposed to the content or campaign at least one time (1+) during the measurement period. Equivalent to reach_persons; included as an explicit effective reach threshold field for consistency with N+ reporting framework used in post-campaign analysis. | Column effective_reach_1plus (BIGINT) in audience.reach_frequency_report',
    `effective_reach_3plus` BIGINT COMMENT 'The count of unique persons exposed to the content or campaign at least three times (3+) during the measurement period. The industry-standard effective reach threshold used to assess whether sufficient frequency was achieved for advertising message recall. Critical for makegoods determination and campaign effectiveness evaluation. | Column effective_reach_3plus (BIGINT) in audience.reach_frequency_report',
    `effective_reach_nplus` BIGINT COMMENT 'The count of unique persons exposed to the content or campaign at least N times (as defined by effective_reach_threshold) during the measurement period. Provides a configurable effective reach metric for custom campaign guarantee structures and advanced frequency analysis. | Column effective_reach_nplus (BIGINT) in audience.reach_frequency_report',
    `effective_reach_threshold` STRING COMMENT 'The minimum number of exposures (N) used to define effective reach for this specific report. Configurable per campaign or client agreement (e.g., 3 for standard campaigns, 5 for high-frequency campaigns). Determines the N+ threshold applied in effective reach calculations beyond the standard 1+ and 3+ fields. | Column effective_reach_threshold (INT) in audience.reach_frequency_report',
    `grp` DECIMAL(18,2) COMMENT 'The sum of all rating points delivered by the campaign or programming block during the measurement period, representing total audience weight without deduplication. Calculated as reach percentage multiplied by average frequency. The primary currency for linear TV advertising transactions and upfront sales guarantees. | Column grp (DECIMAL(10,4)) in audience.reach_frequency_report',
    `hut_rating` DECIMAL(18,2) COMMENT 'The percentage of all television households in the market that had their television sets in use during the measurement period. Sourced from Nielsen Media Research Platform. Used as a contextual benchmark for evaluating audience share and competitive programming performance. | Column hut_rating (DECIMAL(7,4)) in audience.reach_frequency_report',
    `is_makegood_required` BOOLEAN COMMENT 'Indicates whether this reach and frequency report has identified an audience delivery shortfall that requires a makegood (compensatory ad spot) to be issued to the advertiser. Triggers the makegood workflow in Wide Orbit and Salesforce Media Cloud when set to True. | Column is_makegood_required (BOOLEAN) in audience.reach_frequency_report',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether the measurement period falls within a Nielsen sweeps period (an intensive ratings measurement period typically occurring in February, May, July, and November). Sweeps data carries elevated importance for programming decisions, ad rate setting, and affiliate compensation calculations. | Column is_sweeps_period (BOOLEAN) in audience.reach_frequency_report',
    `measurement_period_end_date` DATE COMMENT 'The last date of the measurement window for which reach and frequency metrics are computed. Defines the end boundary of the campaign flight, programming block, or sweeps period being analyzed. | Column measurement_period_end_date (DATE) in audience.reach_frequency_report',
    `measurement_period_start_date` DATE COMMENT 'The first date of the measurement window for which reach and frequency metrics are computed. Defines the start boundary of the campaign flight, programming block, or sweeps period being analyzed. Used in conjunction with measurement_period_end_date to bound the audience measurement interval. | Column measurement_period_start_date (DATE) in audience.reach_frequency_report',
    `measurement_type` STRING COMMENT 'Classifies the type of measurement window for which this report was generated. campaign_flight covers a defined ad campaign run; programming_block covers a scheduled content block; daypart_window covers a standard broadcast daypart; sweeps_period covers an intensive Nielsen ratings measurement period; custom_window covers an ad hoc analysis window. | Column measurement_type (STRING) in audience.reach_frequency_report. Valid values are `campaign_flight|programming_block|daypart_window|sweeps_period|custom_window`',
    `nielsen_report_code` STRING COMMENT 'The native report identifier assigned by the Nielsen Media Research Platform for this reach and frequency dataset. Used for source system traceability, data lineage, and reconciliation between the lakehouse Silver Layer and the Nielsen source system. | Column nielsen_report_code (STRING) in audience.reach_frequency_report',
    `platform_type` STRING COMMENT 'The distribution platform type for which audience reach and frequency is measured. Distinguishes linear (traditional scheduled broadcast), OTT (Over-The-Top streaming), SVOD (Subscription Video On Demand), AVOD (Advertising-Supported Video On Demand), TVOD (Transactional Video On Demand), FAST (Free Ad-Supported Streaming Television), or simulcast (simultaneous multi-platform broadcast). Critical for cross-platform audience deduplication and multi-platform reach reporting. [ENUM-REF-CANDIDATE: linear|OTT|SVOD|AVOD|TVOD|FAST|simulcast — 7 candidates stripped; promote to reference product] | Column platform_type (STRING) in audience.reach_frequency_report',
    `put_rating` DECIMAL(18,2) COMMENT 'The percentage of all persons in the target demographic who were watching television during the measurement period. Sourced from Nielsen Media Research Platform. Used alongside HUT to assess total available audience and calculate audience share for programming decisions. | Column put_rating (DECIMAL(7,4)) in audience.reach_frequency_report',
    `reach_pct` DECIMAL(18,2) COMMENT 'The percentage of the target demographic universe reached at least once during the measurement period, calculated as (reach_persons / universe_estimate) × 100. Expressed as a decimal percentage (e.g., 45.2500 = 45.25%). Used by ad sales for post-campaign delivery reporting and scatter market pricing justification. | Column reach_pct (DECIMAL(7,4)) in audience.reach_frequency_report',
    `reach_persons` BIGINT COMMENT 'The unduplicated count of unique persons within the target demographic segment who were exposed to the content or campaign at least once during the measurement period. The primary reach metric sourced from Nielsen Media Research Platform. Used for post-campaign delivery validation and upfront guarantee reconciliation. | Column reach_persons (BIGINT) in audience.reach_frequency_report',
    `report_generated_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when this reach and frequency report was generated and delivered by the Nielsen Media Research Platform. Represents the business event time, distinct from audit timestamps. Used to track Nielsen data delivery SLAs and post-campaign reporting timeliness. | Column report_generated_timestamp (TIMESTAMP) in audience.reach_frequency_report',
    `report_number` STRING COMMENT 'Externally-known business identifier for this reach and frequency report, sourced from the Nielsen Media Research Platform. Used by ad sales teams to reference specific post-campaign delivery reports in client communications, makegoods negotiations, and upfront guarantee reconciliation. | Column report_number (STRING) in audience.reach_frequency_report. Valid values are `^RF-[0-9]{4}-[0-9]{6}$`',
    `report_status` STRING COMMENT 'Current lifecycle state of the reach and frequency report. draft indicates in-progress computation; preliminary indicates initial Nielsen delivery pending validation; final indicates validated and approved for client delivery; revised indicates a corrected reissue; superseded indicates replaced by a newer version; archived indicates retired from active use. | Column report_status (STRING) in audience.reach_frequency_report. Valid values are `draft|preliminary|final|revised|superseded|archived`',
    `report_version` STRING COMMENT 'The version number of this reach and frequency report, incremented each time a revised or corrected report is issued by Nielsen or reprocessed in the lakehouse. Version 1 represents the initial delivery; subsequent versions represent corrections or revisions. Used to ensure ad sales teams are working with the most current data. | Column report_version (INT) in audience.reach_frequency_report',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.reach_frequency_report',
    `total_impressions` BIGINT COMMENT 'The total number of audience exposures (duplicated) to the content or campaign during the measurement period. Equals reach_persons multiplied by average_frequency. Used as the gross delivery metric for CPM-based advertising transactions and campaign pacing analysis. | Column total_impressions (BIGINT) in audience.reach_frequency_report',
    `trp` DECIMAL(18,2) COMMENT 'The sum of rating points delivered specifically against the target demographic segment during the measurement period. Analogous to GRP but scoped to the defined target audience rather than the total population. Used for targeted advertising guarantee reconciliation and CPRP calculations. | Column trp (DECIMAL(10,4)) in audience.reach_frequency_report',
    `universe_estimate` BIGINT COMMENT 'The total estimated population size (in persons or households) of the target demographic segment in the specified market, as defined by Nielsen. Serves as the denominator for reach percentage calculations and rating point computations. Expressed as an absolute count. | Column universe_estimate (BIGINT) in audience.reach_frequency_report',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.reach_frequency_report',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this reach and frequency report record was last modified in the Silver Layer lakehouse. Tracks revisions, status changes, and data corrections. | Column updated_timestamp (TIMESTAMP) in audience.reach_frequency_report',
    CONSTRAINT pk_reach_frequency_report PRIMARY KEY(`reach_frequency_report_id`)
) COMMENT 'Transactional record capturing computed reach (unduplicated audience count), frequency (average exposures per unique viewer), and effective reach (viewers exposed N+ times) for a defined campaign flight, programming block, or daypart window across a specified demographic segment, market, and measurement period. Sourced from Nielsen Media Research Platform. Used by ad sales for post-campaign delivery validation, makegoods calculation, upfront guarantee reconciliation, and scatter market pricing justification. | Unity Catalog table: media_broadcasting_ecm.audience.reach_frequency_report Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`market_coverage` (
    `market_coverage_id` BIGINT COMMENT 'Unique surrogate identifier for the market coverage record representing a Designated Market Area (DMA) or television market geographic unit. | Column market_coverage_id (BIGINT) in audience.market_coverage',
    `broadcast_license_id` BIGINT COMMENT 'Foreign key linking to compliance.broadcast_license. Business justification: Market coverage definitions derive from broadcast license service contours and DMA assignments. License technical parameters (power, antenna height) determine market boundaries for audience measuremen | Column broadcast_license_id (BIGINT) in compliance.market_coverage',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.market_coverage',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Market coverage (DMA) must link to primary licensed broadcast facility for FCC must-carry compliance, retransmission consent negotiations, local content origination requirements, and emergency alert s | Column primary_broadcast_facility_id (BIGINT) in technology.market_coverage',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_obligation. Business justification: Market coverage areas determine applicable regulatory obligations (must-carry, retransmission consent). DMA and market type drive specific FCC obligations; links market definitions to compliance requi | Column regulatory_obligation_id (BIGINT) in compliance.market_coverage',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.market_coverage',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.market_coverage',
    `blackout_rule_applicable` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout rules apply to this market for sports or syndication exclusivity purposes. True if blackout restrictions can be enforced in this DMA; False otherwise. Used by rights management (Rightsline) and CDN geo-restriction (Akamai) to enforce territorial exclusivity. | Column blackout_rule_applicable (BOOLEAN) in audience.market_coverage',
    `broadcast_standard` STRING COMMENT 'Digital broadcast transmission standard applicable to this market. ATSC (Advanced Television Systems Committee) is the US standard; DVB (Digital Video Broadcasting) is the European standard; ISDB is the Japanese/Brazilian standard; DTMB is the Chinese standard. Determines technical playout and transmission requirements. | Column broadcast_standard (STRING) in audience.market_coverage. Valid values are `ATSC|DVB|ISDB|DTMB`',
    `cable_penetration_rate` DECIMAL(18,2) COMMENT 'Estimated percentage of television households in the DMA that subscribe to cable television (MVPD or vMVPD service). Expressed as a decimal (e.g., 0.6234 = 62.34%). Used for carriage fee negotiations, distribution planning, and ad sales reach projections. | Column cable_penetration_rate (DECIMAL(8,4)) in audience.market_coverage',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code identifying the country in which this market is located (e.g., USA, GBR, CAN). Required for international rights management, windowing decisions, and regulatory jurisdiction determination. | Column country_code (STRING) in audience.market_coverage. Valid values are `^[A-Z]{3}$`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.market_coverage',
    `daylight_saving_observed` BOOLEAN COMMENT 'Indicates whether the DMA observes Daylight Saving Time (DST). True if DST is observed; False if not (e.g., markets in Arizona). Affects daypart scheduling, playout timing, and EPG accuracy in broadcast automation systems. | Column daylight_saving_observed (BOOLEAN) in audience.market_coverage',
    `dma_code` STRING COMMENT 'Nielsen-assigned three-digit numeric code uniquely identifying the Designated Market Area (DMA). This is the externally-known business identifier used across ad sales, ratings reporting, and FCC filings. Sourced from Nielsen Media Research Platform. | Column dma_code (STRING) in audience.market_coverage. Valid values are `^[0-9]{3}$`',
    `dma_rank` STRING COMMENT 'Nielsen-assigned national rank of the DMA by television household universe size, where rank 1 is the largest market (New York). Used for market prioritization in ad sales, upfront negotiations, and carriage fee calculations. Updated annually by Nielsen. | Column dma_rank (INT) in audience.market_coverage',
    `effective_from_date` DATE COMMENT 'The date from which this market coverage record became effective and the DMA definition was valid. Used for temporal versioning of DMA boundary and universe changes, ensuring historical ratings data is associated with the correct market definition. | Column effective_from_date (DATE) in audience.market_coverage',
    `effective_to_date` DATE COMMENT 'The date on which this market coverage record ceased to be effective, typically due to a DMA boundary redefinition, market merger, or discontinuation. Null for currently active market definitions. Supports slowly changing dimension (SCD) history tracking. | Column effective_to_date (DATE) in audience.market_coverage',
    `fcc_market_code` STRING COMMENT 'FCC-assigned market identifier used for must-carry and retransmission consent compliance filings. Maps the Nielsen DMA to the FCCs designated market definition for broadcast licensing, spectrum regulation, and MVPD carriage obligations. Required for regulatory reporting under FCC 47 CFR Part 76. | Column fcc_market_code (STRING) in audience.market_coverage',
    `geographic_boundary_wkt` STRING COMMENT 'Well-Known Text (WKT) representation of the DMAs geographic boundary polygon. Used for spatial analysis, blackout rule enforcement, retransmission consent territory mapping, and OTT/streaming geo-restriction via CDN (Akamai). Conforms to OGC WKT standard. | Column geographic_boundary_wkt (STRING) in audience.market_coverage',
    `hispanic_tv_household_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of television households in the DMA that are Hispanic/Latino, as measured by Nielsen. Expressed as a decimal (e.g., 0.2341 = 23.41%). Used for Spanish-language content distribution decisions, targeted ad sales, and TRP (Target Rating Point) calculations for Hispanic demographic segments. | Column hispanic_tv_household_pct (DECIMAL(8,4)) in audience.market_coverage',
    `hut_base_estimate` DECIMAL(18,2) COMMENT 'Nielsen baseline estimate of the percentage of television households in the DMA that are using television during an average primetime daypart. Expressed as a decimal (e.g., 0.5823 = 58.23%). Used as a reference benchmark for HUT-based audience projections and ad sales planning. | Column hut_base_estimate (DECIMAL(10,4)) in audience.market_coverage',
    `market_name` STRING COMMENT 'Official human-readable name of the Designated Market Area (DMA) or television market as defined by Nielsen (e.g., New York, Los Angeles, Chicago). Used in audience reports, ad sales proposals, and regulatory filings. | Column market_name (STRING) in audience.market_coverage',
    `market_status` STRING COMMENT 'Current lifecycle status of the market coverage record. active indicates the DMA is currently measured and used in audience reporting; inactive indicates it is no longer measured; pending indicates a newly defined market awaiting first measurement; discontinued indicates a market that has been merged or eliminated by Nielsen. | Column market_status (STRING) in audience.market_coverage. Valid values are `active|inactive|pending|discontinued`',
    `market_type` STRING COMMENT 'Classification of the market scope. local indicates a single-city DMA; regional indicates a multi-city or multi-state DMA; national indicates a national aggregate market; international indicates a non-US market territory. Used for ad sales segmentation, carriage fee tiers, and programming distribution decisions. | Column market_type (STRING) in audience.market_coverage. Valid values are `local|regional|national|international`',
    `measurement_frequency` STRING COMMENT 'Frequency at which Nielsen provides audience measurement data for this market. continuous indicates year-round metered measurement (PPM markets); sweeps_only indicates measurement only during sweeps periods (diary markets); quarterly or annual for smaller markets with less frequent measurement cycles. | Column measurement_frequency (STRING) in audience.market_coverage. Valid values are `continuous|sweeps_only|quarterly|annual`',
    `measurement_methodology` STRING COMMENT 'Nielsen measurement methodology applied to this market. PPM (Portable People Meter) is the electronic passive measurement used in large markets; diary is the paper-based recall method used in smaller markets; hybrid indicates a combination of both. Determines the precision and frequency of ratings data available for this market. | Column measurement_methodology (STRING) in audience.market_coverage. Valid values are `PPM|diary|hybrid`',
    `median_household_income` DECIMAL(18,2) COMMENT 'Median annual household income (in USD) for the DMA, sourced from U.S. Census Bureau data as incorporated into Nielsen demographic profiles. Used for audience demographic segmentation, CPM (Cost Per Mille) pricing tiers, and advertiser targeting qualification. | Column median_household_income (DECIMAL(12,2)) in audience.market_coverage',
    `must_carry_applicable` BOOLEAN COMMENT 'Indicates whether FCC must-carry rules apply to broadcast stations in this market, requiring cable operators (MVPDs) to carry local broadcast signals. True if must-carry obligations exist; False otherwise. Critical for retransmission consent negotiations and MVPD carriage compliance. | Column must_carry_applicable (BOOLEAN) in audience.market_coverage',
    `nielsen_source_market_code` STRING COMMENT 'The native market identifier as assigned and used within the Nielsen Media Research Platform source system. Used for data lineage, reconciliation between the lakehouse silver layer and the Nielsen source system, and audit of universe estimate ingestion. | Column nielsen_source_market_code (STRING) in audience.market_coverage',
    `nielsen_station_index` STRING COMMENT 'Total number of television stations measured by Nielsen within this DMA. Indicates the competitive landscape of the local market and is used in share calculations and ad sales competitive analysis. | Column nielsen_station_index (INT) in audience.market_coverage',
    `ott_penetration_rate` DECIMAL(18,2) COMMENT 'Estimated percentage of television households in the DMA that access video content via OTT (Over-The-Top) streaming services. Expressed as a decimal. Used for digital distribution planning, SVOD/AVOD audience projections, and DAI (Dynamic Ad Insertion) inventory estimation. | Column ott_penetration_rate (DECIMAL(8,4)) in audience.market_coverage',
    `population_universe` BIGINT COMMENT 'Nielsen-estimated total population (persons 2+) residing within the DMA boundary. Used as the denominator for person-based ratings metrics including PUT (Persons Using Television) and TRP (Target Rating Point) calculations. Updated annually in the Nielsen universe estimates release. | Column population_universe (BIGINT) in audience.market_coverage',
    `primary_language` STRING COMMENT 'ISO 639-1 or ISO 639-2 language code representing the predominant language spoken in the DMA (e.g., en for English, es for Spanish). Used for content localization decisions, Spanish-language network distribution, and audience demographic targeting. | Column primary_language (STRING) in audience.market_coverage. Valid values are `^[a-z]{2,3}$`',
    `principal_city` STRING COMMENT 'Name of the primary city or metropolitan area that anchors and names the DMA (e.g., New York, Los Angeles, Chicago). Used in market identification, ad sales materials, and regulatory filings. | Column principal_city (STRING) in audience.market_coverage',
    `put_base_estimate` DECIMAL(18,2) COMMENT 'Nielsen baseline estimate of the percentage of persons (2+) in the DMA who are using television during an average primetime daypart. Expressed as a decimal (e.g., 0.4612 = 46.12%). Used as a reference benchmark for PUT-based audience projections and TRP calculations. | Column put_base_estimate (DECIMAL(10,4)) in audience.market_coverage',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this market coverage record was first created in the Databricks Lakehouse Silver Layer. Used for audit trail, data lineage tracking, and compliance with SOX financial reporting controls that require data provenance. | Column record_created_timestamp (TIMESTAMP) in audience.market_coverage',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this market coverage record was most recently updated in the Databricks Lakehouse Silver Layer. Used for change detection, incremental processing, and audit trail maintenance. | Column record_updated_timestamp (TIMESTAMP) in audience.market_coverage',
    `regulatory_jurisdiction` STRING COMMENT 'Primary broadcast regulatory authority governing this market. FCC for US markets; Ofcom for UK markets; CRTC for Canadian markets; ACMA for Australian markets; other for all other jurisdictions. Determines applicable must-carry, retransmission consent, content standards, and licensing requirements. | Column regulatory_jurisdiction (STRING) in audience.market_coverage. Valid values are `FCC|Ofcom|CRTC|ACMA|other`',
    `retransmission_consent_applicable` BOOLEAN COMMENT 'Indicates whether retransmission consent rules apply to broadcast stations in this market, allowing broadcasters to negotiate compensation from MVPDs for carriage of their signals. True if retransmission consent is applicable; False otherwise. | Column retransmission_consent_applicable (BOOLEAN) in audience.market_coverage',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.market_coverage',
    `state_province_code` STRING COMMENT 'ISO 3166-2 two-letter state or province code of the primary state in which the DMAs principal city is located (e.g., NY, CA, IL). Used for geographic segmentation, blackout rule enforcement, and retransmission consent jurisdiction determination. | Column state_province_code (STRING) in audience.market_coverage. Valid values are `^[A-Z]{2}$`',
    `sweeps_participation` BOOLEAN COMMENT 'Indicates whether this market participates in Nielsen sweeps periods (intensive ratings measurement periods in February, May, July, and November). True if the market is measured during sweeps; False if it is a non-sweeps market. Affects programming scheduling strategy and ad sales pricing. | Column sweeps_participation (BOOLEAN) in audience.market_coverage',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the primary time zone of the DMA (e.g., America/New_York, America/Los_Angeles). Critical for daypart scheduling, playout automation in Ericsson MediaFirst, EPG (Electronic Program Guide) alignment, and ad scheduling in Wide Orbit Traffic system. | Column time_zone (STRING) in audience.market_coverage',
    `total_counties` STRING COMMENT 'Total number of counties or county-equivalents included within the DMA boundary. Nielsen defines DMA boundaries at the county level. Used for geographic coverage analysis, must-carry compliance, and retransmission consent territory verification. | Column total_counties (INT) in audience.market_coverage',
    `tv_household_universe` BIGINT COMMENT 'Nielsen-estimated total number of television households within the DMA boundary. This is the principal quantitative measurement fact for the market and serves as the denominator for all local ratings calculations, GRP/TRP computations, and CPM-based ad pricing. Updated annually in the Nielsen universe estimates release. | Column tv_household_universe (BIGINT) in audience.market_coverage',
    `universe_effective_date` DATE COMMENT 'The date from which the current Nielsen universe estimates (TV household and population) became effective for this market. Used to track the currency of universe data and ensure ratings calculations use the correct denominator for the applicable measurement period. | Column universe_effective_date (DATE) in audience.market_coverage',
    `universe_estimate_year` STRING COMMENT 'The calendar year for which the Nielsen universe estimates (TV household and population figures) are valid. Nielsen releases updated universe estimates annually, typically effective in the fall. Used to version and audit the universe figures used in ratings calculations. | Column universe_estimate_year (INT) in audience.market_coverage',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.market_coverage',
    CONSTRAINT pk_market_coverage PRIMARY KEY(`market_coverage_id`)
) COMMENT 'Master record defining a Designated Market Area (DMA) or television market — the geographic unit used for local audience measurement. Captures DMA rank, DMA code, market name, TV household universe estimate, population universe, geographic boundaries, and applicable measurement methodology (PPM vs. diary). Aligns with Nielsen DMA definitions and FCC market designations for must-carry and retransmission consent compliance. | Unity Catalog table: media_broadcasting_ecm.audience.market_coverage Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`engagement_event` (
    `engagement_event_id` BIGINT COMMENT 'Unique surrogate identifier for each discrete digital audience engagement action captured on OTT/streaming platforms. Primary key for this product in the Databricks Silver Layer. | Column engagement_event_id (BIGINT) in audience.engagement_event',
    `sales_campaign_id` BIGINT COMMENT 'Identifier for the advertising campaign associated with this engagement event, populated when the event is triggered within or adjacent to an ad pod. Supports DAI (Dynamic Ad Insertion) attribution and campaign performance measurement. | Column ad_campaign_id (BIGINT) in sales.engagement_event',
    `advertiser_id` BIGINT COMMENT 'Foreign key linking to sales.advertiser. Business justification: Engagement events (clicks, completions, interactions) are attributed to advertisers for performance reporting, creative effectiveness analysis, and cross-campaign optimization. Essential for digital/s | Column advertiser_id (BIGINT) in sales.engagement_event',
    `compliance_consent_record_id` BIGINT COMMENT 'Foreign key linking to compliance.consent_record. Business justification: Engagement tracking requires consent validation for data processing legality under GDPR/CCPA. Essential for demonstrating lawful basis for behavioral analytics and targeted advertising. | Column compliance_consent_record_id (BIGINT) in compliance.engagement_event',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Engagement analytics require content rating context for COPPA compliance validation and parental control enforcement. Necessary to prevent unauthorized data collection from children viewing age-restri | Column compliance_content_rating_id (BIGINT) in compliance.engagement_event',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Digital engagement events are classified by Nielsen demographic segments for audience measurement integration. The nielsen_demo_code should be replaced with FK to demographic_segment for consistency w | Column demographic_segment_id (BIGINT) in audience.engagement_event',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.engagement_event',
    `broadcast_facility_id` BIGINT COMMENT 'Foreign key linking to technology.broadcast_facility. Business justification: Engagement events must track originating broadcast facility for streaming performance analysis, CDN edge optimization, and correlating viewer experience with infrastructure health. Critical for NOC in | Column originating_broadcast_facility_id (BIGINT) in technology.engagement_event',
    `ott_platform_id` BIGINT COMMENT 'Identifier for the distribution platform (e.g., OTT app, SVOD service, AVOD channel, FAST channel) on which the engagement event occurred. Enables multi-platform distribution and audience analytics. | Column platform_id (BIGINT) in distribution.engagement_event',
    `playback_session_id` BIGINT COMMENT 'Anonymized identifier for the streaming session during which this engagement event occurred. Links all events within a single continuous viewing session for session-level analytics. Sourced from Adobe Experience Platform session context. | Column session_id (BIGINT) in distribution.engagement_event',
    `privacy_request_id` BIGINT COMMENT 'Foreign key linking to compliance.privacy_request. Business justification: Privacy requests must locate and process engagement event data for GDPR/CCPA compliance. Links requests to behavioral data for subject access reports and deletion fulfillment. | Column privacy_request_id (BIGINT) in compliance.engagement_event',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level engagement tracking identifies drop-off points, rewatch behavior, and scene-level audience response. Used for post-production feedback, marketing clip selection, and editorial pacing ana | Column production_episode_id (BIGINT) in production.engagement_event',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Engagement events (play, pause, seek, rewind) are tracked per production project for content optimization, A/B testing, and editorial feedback. Essential for streaming platform analytics and content d | Column production_project_id (BIGINT) in production.engagement_event',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: Linear engagement events (tune-in, tune-out, ad interactions) must link to schedule slots for slot-level engagement analysis, ad effectiveness measurement, and audience flow tracking. Creates schedule | Column schedule_slot_id (BIGINT) in scheduling.engagement_event',
    `segment_id` BIGINT COMMENT 'Foreign key linking to audience.audience_segment. Business justification: Engagement events are tagged with custom audience segments for behavioral targeting and activation. The audience_segment_code should be replaced with FK to audience_segment master for consistency and  | Column segment_id (BIGINT) in audience.engagement_event',
    `title_id` BIGINT COMMENT 'Identifier for the content asset (programme, episode, clip, or ad) against which this engagement event was recorded. Enables content-level audience behaviour analysis for programming decisions. | Column title_id (BIGINT) in content.engagement_event',
    `viewer_profile_id` BIGINT COMMENT 'Anonymized identifier for the audience member or household profile that generated this engagement event. Sourced from Adobe Experience Platform unified profile. Used for audience segmentation and ad targeting without exposing personal identity. | Column viewer_profile_id (BIGINT) in subscriber.engagement_event',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.engagement_event',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.engagement_event',
    `ad_pod_position` STRING COMMENT 'Ordinal position of the advertisement within its ad pod (group of ads in a break) at the time of the engagement event. Populated only when is_ad_event is True. Used to analyse viewer drop-off rates by pod position and optimise ad pod sequencing for revenue assurance. | Column ad_pod_position (INT) in audience.engagement_event',
    `app_version` STRING COMMENT 'Version string of the OTT/streaming application that captured the engagement event (e.g., 4.2.1). Used to correlate engagement behaviour with app release cycles and identify version-specific anomalies in audience interaction patterns. | Column app_version (STRING) in audience.engagement_event. Valid values are `^d+.d+.d+$`',
    `bitrate_kbps` STRING COMMENT 'Actual bitrate in kilobits per second of the stream being delivered at the time of the engagement event. Sourced from Akamai CDN performance telemetry. Used alongside stream_quality to assess CDN delivery performance and its impact on audience engagement. | Column bitrate_kbps (INT) in audience.engagement_event',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a geographic broadcast restriction (blackout) was enforced for this viewer at the time of the engagement event (True) or not (False). Supports FCC blackout compliance reporting and rights management audit trails. | Column blackout_applied (BOOLEAN) in audience.engagement_event',
    `buffering_duration_ms` STRING COMMENT 'Total duration of buffering experienced by the viewer immediately preceding or during this engagement event, in milliseconds. Sourced from Adobe Experience Platform quality-of-experience telemetry. Used to correlate buffering events with pause and abandonment engagement actions. | Column buffering_duration_ms (INT) in audience.engagement_event',
    `content_duration_ms` BIGINT COMMENT 'Total duration of the content asset in milliseconds at the time of the engagement event. Used in conjunction with content_position_ms to compute completion percentage and engagement depth score. Sourced from Dalet Galaxy asset metadata. | Column content_duration_ms (BIGINT) in audience.engagement_event',
    `content_genre` STRING COMMENT 'Primary genre classification of the content asset associated with this engagement event (e.g., Drama, News, Sports, Comedy, Documentary). Sourced from Dalet Galaxy asset metadata. Used for genre-level audience behaviour analysis and programming acquisition decisions. | Column content_genre (STRING) in audience.engagement_event',
    `content_position_ms` BIGINT COMMENT 'Playback position within the content asset at the moment the engagement event was triggered, expressed in milliseconds from the start of the content. Core EVENT_PAYLOAD_OR_VALUE for this event log. Enables precise engagement depth analysis, completion rate calculation, and identification of drop-off points. | Column content_position_ms (BIGINT) in audience.engagement_event',
    `content_rating` STRING COMMENT 'Motion Picture Association (MPA) or TV Parental Guidelines content rating of the asset at the time of the engagement event. Used for COPPA compliance (childrens content restrictions), audience demographic validation, and parental control enforcement. [ENUM-REF-CANDIDATE: G|PG|PG-13|R|NC-17|TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA — promote to reference product] | Column content_rating (STRING) in audience.engagement_event',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.engagement_event',
    `data_privacy_consent` STRING COMMENT 'Viewers data privacy consent status at the time of the engagement event, governing permissible use of this record for analytics, personalisation, and ad targeting. Sourced from Adobe Experience Platform consent management. Mandatory for GDPR Article 6 lawful basis determination and CCPA opt-out compliance. | Column data_privacy_consent (STRING) in audience.engagement_event. Valid values are `full_consent|analytics_only|no_consent|withdrawn`',
    `daypart` STRING COMMENT 'Broadcast daypart time segment in which the engagement event occurred, classified per industry-standard daypart definitions. Used for audience measurement reporting, ad sales daypart targeting, and programming scheduling decisions. [ENUM-REF-CANDIDATE: early_morning|daytime|early_fringe|prime_access|prime|late_news|late_fringe|overnight — promote to reference product] | Column daypart (STRING) in audience.engagement_event',
    `device_os` STRING COMMENT 'Operating system of the device that generated the engagement event (e.g., iOS, Android, tvOS, Roku OS, Fire OS, Windows, macOS). Sourced from Adobe Experience Platform device context. Supports technical platform compatibility analysis and audience reach reporting. | Column device_os (STRING) in audience.engagement_event',
    `device_type` STRING COMMENT 'Category of the physical device on which the engagement event was generated. Enables device-level audience segmentation and platform distribution analysis. [ENUM-REF-CANDIDATE: smart_tv|mobile|tablet|desktop|set_top_box|gaming_console|other — promote to reference product] | Column device_type (STRING) in audience.engagement_event',
    `drm_scheme` STRING COMMENT 'DRM (Digital Rights Management) protection scheme active on the content stream at the time of the engagement event. Used for rights compliance verification and to ensure content is consumed within licensed windows and territories. Supports Rightsline rights enforcement reporting. | Column drm_scheme (STRING) in audience.engagement_event. Valid values are `widevine|fairplay|playready|clearkey|none`',
    `engagement_depth_score` DECIMAL(18,2) COMMENT 'Normalised score (0.00–100.00) representing the depth of audience engagement at the time of the event, calculated by Adobe Experience Platform based on playback position relative to content duration, interaction frequency, and event type weighting. Key metric for non-linear audience behaviour analysis and ad targeting propensity modelling. | Column engagement_depth_score (DECIMAL(5,2)) in audience.engagement_event',
    `event_status` STRING COMMENT 'Processing lifecycle status of the engagement event record in the Silver Layer. valid indicates the event passed all quality checks; invalid indicates a data quality failure; duplicate indicates a repeated event suppressed from analytics; quarantined indicates the event is held pending investigation. | Column event_status (STRING) in audience.engagement_event. Valid values are `valid|invalid|duplicate|quarantined`',
    `event_timestamp` TIMESTAMP COMMENT 'Precise UTC timestamp recording when the engagement action occurred on the viewers device. Principal EVENT_TIMESTAMP for this event log entity. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX. Used for time-series audience behaviour analysis, daypart analytics, and sweeps period reporting. | Column event_timestamp (TIMESTAMP) in audience.engagement_event',
    `event_type` STRING COMMENT 'Categorical discriminator identifying the specific audience interaction captured: play (content start/resume), pause (playback halted), seek (position jump forward), rewind (position jump backward), share (social distribution action), like (positive sentiment signal), comment (text interaction), complete (full content consumption). Core EVENT_TYPE_OR_CHANNEL field for non-linear audience behaviour analysis. [ENUM-REF-CANDIDATE: play|pause|seek|rewind|share|like|comment|complete — 8 candidates stripped; promote to reference product] | Column event_type (STRING) in audience.engagement_event',
    `geo_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the viewers geographic location at the time of the engagement event, derived from IP geolocation. Used for territorial rights compliance (blackout enforcement, holdback windows), audience reach reporting by geography, and regulatory jurisdiction determination. | Column geo_country_code (STRING) in audience.engagement_event. Valid values are `^[A-Z]{3}$`',
    `geo_region_code` STRING COMMENT 'ISO 3166-2 subdivision code (state, province, or region) of the viewers location at the time of the engagement event. Used for sub-national blackout enforcement, regional audience measurement, and daypart-adjusted analytics. | Column geo_region_code (STRING) in audience.engagement_event. Valid values are `^[A-Z]{2}-[A-Z0-9]{1,3}$`',
    `is_ad_event` BOOLEAN COMMENT 'Indicates whether this engagement event occurred during an advertisement (True) or during editorial content (False). Critical for separating content engagement metrics from ad engagement metrics in AVOD and DAI (Dynamic Ad Insertion) analytics. | Column is_ad_event (BOOLEAN) in audience.engagement_event',
    `is_concurrent_stream` BOOLEAN COMMENT 'Indicates whether this engagement event occurred on a stream that was running concurrently with another active stream on the same viewer account (True) or not (False). Used for concurrent stream limit enforcement per subscription terms and HUT (Homes Using Television) measurement. | Column is_concurrent_stream (BOOLEAN) in audience.engagement_event',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether the engagement event occurred during a Nielsen sweeps measurement period (True) or outside of it (False). Sweeps periods are intensive ratings measurement windows critical for ad sales pricing and programming strategy. Enables sweeps vs. non-sweeps audience behaviour comparison. | Column is_sweeps_period (BOOLEAN) in audience.engagement_event',
    `isan_code` STRING COMMENT 'ISAN (International Standard Audiovisual Number) of the content asset associated with this engagement event. Provides a globally unique, persistent identifier for the audiovisual work independent of platform or distribution channel. Supports rights management, royalty calculation, and regulatory reporting. | Column isan_code (STRING) in audience.engagement_event. Valid values are `^ISAN [0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}$`',
    `received_timestamp` TIMESTAMP COMMENT 'UTC timestamp when the engagement event was received and ingested by Adobe Experience Platform. Distinct from event_timestamp (client-side occurrence time). Used to measure event latency, detect clock skew, and support data quality auditing in the Silver Layer pipeline. | Column received_timestamp (TIMESTAMP) in audience.engagement_event',
    `referral_source` STRING COMMENT 'Channel or mechanism through which the viewer arrived at the content that triggered this engagement event. Used for audience acquisition attribution, marketing campaign effectiveness analysis, and content discovery optimisation. [ENUM-REF-CANDIDATE: direct|search|social|email|push_notification|in_app|external_link — promote to reference product] | Column referral_source (STRING) in audience.engagement_event',
    `seek_from_position_ms` BIGINT COMMENT 'Playback position in milliseconds from which the viewer initiated a seek or rewind action. Populated only when event_type is seek or rewind. Combined with content_position_ms (seek-to position) to measure skip behaviour and identify content segments that audiences skip or revisit. | Column seek_from_position_ms (BIGINT) in audience.engagement_event',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.engagement_event',
    `source_system_event_code` STRING COMMENT 'Original event identifier assigned by Adobe Experience Platform at the point of capture, before Silver Layer surrogate key assignment. Used for data lineage tracing, deduplication, and reconciliation between the Silver Layer and the Adobe Experience Platform source system. | Column source_system_event_code (STRING) in audience.engagement_event',
    `stream_quality` STRING COMMENT 'Adaptive bitrate (ABR) quality tier of the stream at the time of the engagement event, reflecting the HLS or MPEG-DASH rendition being delivered by the CDN. Used to correlate stream quality with engagement behaviour and identify quality-driven churn signals. | Column stream_quality (STRING) in audience.engagement_event. Valid values are `4K_UHD|1080p|720p|480p|360p|audio_only`',
    `subscription_tier` STRING COMMENT 'Subscription or access tier of the viewer at the time of the engagement event, reflecting the monetisation model under which content was consumed. Sourced from Zuora subscription billing. Used to segment engagement behaviour by revenue tier for ARPU analysis and churn prediction. | Column subscription_tier (STRING) in audience.engagement_event. Valid values are `svod|avod|tvod|free|premium|trial`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.engagement_event',
    CONSTRAINT pk_engagement_event PRIMARY KEY(`engagement_event_id`)
) COMMENT 'Transactional record capturing a discrete digital audience engagement action on OTT/streaming platforms — including play, pause, seek, rewind, share, like, comment, and content completion events. Sourced from Adobe Experience Platform. Captures event type, content identifier, viewer session identifier (anonymized), platform, device, timestamp, and engagement depth score. Enables non-linear audience behavior analysis for programming and ad targeting. | Unity Catalog table: media_broadcasting_ecm.audience.engagement_event';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`audience_profile` (
    `audience_profile_id` BIGINT COMMENT 'Unique surrogate identifier for the audience profile record in the Silver Layer lakehouse. Primary key for this entity. | Column audience_profile_id (BIGINT) in audience.audience_profile',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Audience profiles are associated with specific DMAs for geographic targeting and measurement. The dma_code should be replaced with FK to market_coverage for consistency with other products. Country_co | Column market_coverage_id (BIGINT) in audience.audience_profile',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.audience_profile',
    `panel_id` BIGINT COMMENT 'Pseudonymized identifier assigned by Nielsen Media Research to link this audience profile to a Nielsen panel household or individual. Enables direct integration of Nielsen ratings, GRP/TRP, and demographic data. Null for non-panel profiles. | Column nielsen_panel_id (BIGINT) in audience.audience_profile',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.audience_profile',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.audience_profile',
    `ad_receptivity_score` DECIMAL(18,2) COMMENT 'Propensity score (0.00–100.00) indicating this audience members likelihood to engage with advertising content, derived from behavioral signals in Adobe AEP and viewing pattern analysis. Used by ad sales teams for premium audience packaging and CPM pricing optimization. | Column ad_receptivity_score (DECIMAL(5,2)) in audience.audience_profile',
    `aep_profile_code` STRING COMMENT 'Unique profile identifier from Adobe Experience Platform (AEP) used to link behavioral engagement data, segment memberships, and journey analytics to this audience profile. Enables personalization and digital engagement enrichment. | Column aep_profile_code (STRING) in audience.audience_profile',
    `aep_segment_membership` STRING COMMENT 'Comma-delimited list of Adobe Experience Platform (AEP) audience segment IDs to which this profile currently belongs. Segments represent behavioral, demographic, or propensity-based audience groups used for personalization, ad targeting, and journey activation. | Column aep_segment_membership (STRING) in audience.audience_profile',
    `avg_session_duration_minutes` DECIMAL(18,2) COMMENT 'Average duration in minutes of a single viewing session for this audience member, derived from set-top box or streaming platform telemetry. Represents Time Spent Viewing (TSV) at the individual level. Used for engagement scoring and content performance analytics. | Column avg_session_duration_minutes (DECIMAL(8,2)) in audience.audience_profile',
    `ccpa_opt_out` BOOLEAN COMMENT 'Indicates whether this California-resident audience member has exercised their CCPA right to opt out of the sale or sharing of their personal information. When TRUE, this profile must be excluded from data sharing with third-party ad networks and data clean rooms. | Column ccpa_opt_out (BOOLEAN) in audience.audience_profile',
    `consent_last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent change to any consent or privacy flag (GDPR consent status, CCPA opt-out, COPPA flag) for this audience profile. Critical for regulatory audit trails demonstrating timely consent management and data processing compliance. | Column consent_last_updated_timestamp (TIMESTAMP) in audience.audience_profile',
    `content_affinity_genre` STRING COMMENT 'Top inferred content genre affinity for this audience member (e.g., news, sports, drama, reality, documentary), derived from viewing history and behavioral signals in Adobe AEP. Used for content recommendation, programming decisions, and audience-targeted ad sales. [ENUM-REF-CANDIDATE: news|sports|drama|comedy|reality|documentary|entertainment|kids|lifestyle|sci_fi — promote to reference product] | Column content_affinity_genre (STRING) in audience.audience_profile',
    `coppa_protected` BOOLEAN COMMENT 'Indicates whether this audience profile is subject to COPPA (Childrens Online Privacy Protection Act) protections, meaning the inferred or declared age is under 13. When TRUE, ad targeting, data sharing, and behavioral tracking are strictly restricted per COPPA compliance requirements. | Column coppa_protected (BOOLEAN) in audience.audience_profile',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the audience members country of residence. Used for rights windowing, content holdback enforcement, GDPR/CCPA jurisdictional compliance, and international distribution analytics. | Column country_code (STRING) in audience.audience_profile. Valid values are `^[A-Z]{3}$`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.audience_profile',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience profile record was first created in the Silver Layer lakehouse, either through initial identity resolution, panel enrollment, or first-party data ingestion. Audit trail for data lineage and GDPR data minimization compliance. | Column created_timestamp (TIMESTAMP) in audience.audience_profile',
    `data_clean_room_eligible` BOOLEAN COMMENT 'Indicates whether this audience profile is eligible for inclusion in data clean room matching operations with advertising partners. Eligibility is determined by consent status, CCPA opt-out flag, COPPA protection status, and contractual data sharing agreements. | Column data_clean_room_eligible (BOOLEAN) in audience.audience_profile',
    `daypart_preference` STRING COMMENT 'Preferred daypart (time segment of the broadcast day) during which this audience member most frequently views content. Dayparts are standard broadcast industry time segments used for ad scheduling, upfront sales, and audience guarantee reporting. | Column daypart_preference (STRING) in audience.audience_profile. Valid values are `early_morning|daytime|early_fringe|prime_time|late_night|overnight`',
    `device_graph_code` STRING COMMENT 'Cross-device graph linkage identifier that associates this audience profile with a cluster of known devices (smart TV, mobile, desktop, STB). Sourced from identity resolution providers or Adobe AEP device graph. Enables multi-screen reach and frequency measurement. | Column device_graph_code (STRING) in audience.audience_profile',
    `enrichment_source_version` STRING COMMENT 'Version identifier of the third-party enrichment data package (e.g., Nielsen demographic file version, Adobe AEP segment refresh batch ID) used to populate inferred attributes on this profile. Enables data lineage tracing and reproducibility of audience segment definitions. | Column enrichment_source_version (STRING) in audience.audience_profile',
    `gdpr_consent_status` STRING COMMENT 'Current GDPR consent status for processing this audience members personal data for audience measurement and advertising purposes. granted permits processing; denied or withdrawn restricts processing; not_applicable for non-EU audience members. Drives data processing eligibility. | Column gdpr_consent_status (STRING) in audience.audience_profile. Valid values are `granted|denied|withdrawn|not_applicable`',
    `household_size` STRING COMMENT 'Estimated number of persons in the audience household, derived from Nielsen panel data or set-top box signals. Used in HUT (Homes Using Television) and PUT (Persons Using Television) calculations for audience measurement reporting. | Column household_size (INT) in audience.audience_profile',
    `hut_eligible` BOOLEAN COMMENT 'Indicates whether this household-level audience profile is eligible to be counted in HUT (Homes Using Television) calculations. HUT measures the percentage of TV-equipped homes actively watching television during a given time period, a foundational metric for broadcast ratings. | Column hut_eligible (BOOLEAN) in audience.audience_profile',
    `identity_confidence_score` DECIMAL(18,2) COMMENT 'Confidence score (0.00–100.00) representing the reliability of the identity resolution that constructed this audience profile. Higher scores indicate stronger deterministic matching (e.g., authenticated login); lower scores indicate probabilistic device-graph inference. Used to qualify profiles for premium ad targeting. | Column identity_confidence_score (DECIMAL(5,2)) in audience.audience_profile',
    `identity_hash` STRING COMMENT 'SHA-256 pseudonymized hash of the audience members primary identity (e.g., email or subscriber ID) used for cross-platform identity resolution without exposing raw PII. Enables privacy-safe linkage across Nielsen, Adobe AEP, and first-party data sources. | Column identity_hash (STRING) in audience.audience_profile. Valid values are `^[a-fA-F0-9]{64}$`',
    `identity_source` STRING COMMENT 'Originating source of the audience identity construction: first_party (subscriber or app registration data), nielsen (Nielsen Media Research panel linkage), adobe_aep (Adobe Experience Platform profile), set_top_box (STB device-level data), clean_room (data clean room match), or modeled (probabilistic inference). | Column identity_source (STRING) in audience.audience_profile. Valid values are `first_party|nielsen|adobe_aep|set_top_box|clean_room|modeled`',
    `income_band` STRING COMMENT 'Inferred household income band derived from third-party demographic enrichment (Nielsen, data clean rooms). Used for premium audience segmentation in upfront and scatter market ad sales, enabling CPM pricing differentiation by audience affluence. | Column income_band (STRING) in audience.audience_profile. Valid values are `under_25k|25k_50k|50k_75k|75k_100k|100k_150k|over_150k`',
    `inferred_age_band` STRING COMMENT 'Inferred age demographic band for the audience member, derived from Nielsen panel data, set-top box signals, or modeled enrichment. Used for GRP/TRP demographic targeting and ad sales audience guarantees. Not directly collected from the individual. | Column inferred_age_band (STRING) in audience.audience_profile. Valid values are `18-24|25-34|35-44|45-54|55-64|65+`',
    `inferred_gender` STRING COMMENT 'Inferred gender of the audience member derived from panel data or modeled signals. Used for demographic audience targeting in ad sales (GRP/TRP calculations) and programming decisions. Not directly collected. | Column inferred_gender (STRING) in audience.audience_profile. Valid values are `male|female|unknown`',
    `last_seen_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent observed audience activity event (viewing session, app interaction, or platform login) for this profile. Used to determine audience recency, drive re-engagement campaigns, and calculate viewing recency metrics. | Column last_seen_timestamp (TIMESTAMP) in audience.audience_profile',
    `nielsen_grp_index` DECIMAL(18,2) COMMENT 'Indexed GRP (Gross Rating Point) score for this audience profile relative to the total population, sourced from Nielsen Media Research. A GRP index above 100 indicates above-average exposure to rated content. Used in ad sales audience guarantees and upfront negotiations. | Column nielsen_grp_index (DECIMAL(8,4)) in audience.audience_profile',
    `panel_weight_factor` DECIMAL(18,2) COMMENT 'Statistical weighting factor assigned by Nielsen to this panel member profile to project panel observations to the total population. Applied in GRP, TRP, HUT, and PUT calculations. Null for non-panel (modeled or first-party only) profiles. | Column panel_weight_factor (DECIMAL(10,6)) in audience.audience_profile',
    `platform_preference` STRING COMMENT 'Primary viewing platform preference inferred from behavioral signals: linear_tv (traditional scheduled broadcast), svod (Subscription Video On Demand), avod (Advertising-Supported VOD), tvod (Transactional VOD), fast (Free Ad-Supported Streaming TV), ott (Over-The-Top), mvpd (Multichannel Video Programming Distributor), or vmvpd (Virtual MVPD). Drives distribution strategy and ad product targeting. [ENUM-REF-CANDIDATE: linear_tv|svod|avod|tvod|fast|ott|mvpd|vmvpd — 8 candidates stripped; promote to reference product] | Column platform_preference (STRING) in audience.audience_profile',
    `primary_device_type` STRING COMMENT 'The primary device type through which this audience member most frequently consumes content, derived from device graph and behavioral data. Used for CDN delivery optimization, ad format targeting, and platform analytics. | Column primary_device_type (STRING) in audience.audience_profile. Valid values are `smart_tv|mobile|desktop|tablet|set_top_box|streaming_stick`',
    `profile_status` STRING COMMENT 'Current lifecycle state of the audience profile. suppressed indicates a privacy opt-out or regulatory hold; pending_consent indicates consent collection is in progress; purged indicates the record has been anonymized per GDPR/CCPA erasure request. | Column profile_status (STRING) in audience.audience_profile. Valid values are `active|inactive|suppressed|pending_consent|purged`',
    `profile_type` STRING COMMENT 'Classification of the audience profile record: individual (single person identity), household (aggregated household unit), panel_member (Nielsen or equivalent panel participant), or modeled (synthetically constructed from behavioral signals without direct identity linkage). | Column profile_type (STRING) in audience.audience_profile. Valid values are `individual|household|panel_member|modeled`',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.audience_profile',
    `sweeps_period_flag` BOOLEAN COMMENT 'Indicates whether this audience profiles measurement data was captured during a Nielsen Sweeps period (intensive ratings measurement period: February, May, July, November). Sweeps data carries higher statistical weight in ratings calculations and programming decisions. | Column sweeps_period_flag (BOOLEAN) in audience.audience_profile',
    `trp_index` DECIMAL(18,2) COMMENT 'Indexed TRP (Target Rating Point) score representing this audience members contribution to a specific demographic target groups rating. Distinct from GRP in that it measures reach within a defined target demographic. Used for demographic-specific ad campaign planning and post-campaign analysis. | Column trp_index (DECIMAL(8,4)) in audience.audience_profile',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.audience_profile',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this audience profile record, triggered by enrichment refresh, consent status change, identity graph update, or behavioral signal ingestion. Used for data freshness monitoring and incremental processing. | Column updated_timestamp (TIMESTAMP) in audience.audience_profile',
    `viewing_recency_days` STRING COMMENT 'Number of days since this audience member last engaged with any content on any tracked platform. Used for audience recency segmentation, churn prediction, and re-engagement campaign targeting. Lower values indicate more recently active audiences. | Column viewing_recency_days (INT) in audience.audience_profile',
    `weekly_viewing_frequency` STRING COMMENT 'Average number of distinct viewing sessions per week for this audience member, calculated over a rolling 4-week window. Represents the Frequency dimension of audience measurement (average exposures per viewer). Used in reach and frequency reporting for ad campaign delivery. | Column weekly_viewing_frequency (INT) in audience.audience_profile',
    CONSTRAINT pk_audience_profile PRIMARY KEY(`audience_profile_id`)
) COMMENT 'Anonymized/pseudonymized master record representing a unique audience member or household identity constructed from first-party data (subscriber records, app registrations, set-top box data) and third-party enrichment (Nielsen, Adobe AEP, data clean rooms). Captures hashed identity, device graph linkage, inferred demographic attributes, content affinity scores, platform preferences, viewing recency/frequency, and consent/privacy flags per GDPR, CCPA, and COPPA. Distinct from the subscriber SSOT in the subscriber domain — this is the audience intelligence and behavioral record, not the billing or subscription identity. | Unity Catalog table: media_broadcasting_ecm.audience.audience_profile Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`measurement_methodology` (
    `measurement_methodology_id` BIGINT COMMENT 'Unique surrogate identifier for each audience measurement methodology record in the Silver Layer lakehouse. Primary key for this reference master entity. [_canonical_skip_reason: REFERENCE_LOOKUP — this entity is a reference master defining enumerated measurement methodologies; per-role minimums are exempt, but comprehensive coverage is still applied given the business complexity of this domain.] | Column measurement_methodology_id (BIGINT) in audience.measurement_methodology',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.measurement_methodology',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.measurement_methodology',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.measurement_methodology',
    `accreditation_body` STRING COMMENT 'The name of the independent body that has accredited or audited this measurement methodology (e.g., Media Rating Council (MRC), Joint Industry Committee (JIC), BARB, Ofcom). Supports multi-market operations where different accreditation bodies govern different geographies. | Column accreditation_body (STRING) in audience.measurement_methodology',
    `applicable_market_types` STRING COMMENT 'Comma-separated list of market types where this methodology is valid (e.g., national, local_dma, regional, international). Nielsen PPM is typically used in national and large local DMA markets; diary methodology is used in smaller local markets. Determines which geographic market audience records can be attributed to this methodology. | Column applicable_market_types (STRING) in audience.measurement_methodology',
    `applicable_platform_types` STRING COMMENT 'Comma-separated list of platform types to which this methodology applies (e.g., linear_tv, ott_streaming, radio, digital_display, podcast). Governs which viewership records and distribution channels can be measured and reported using this methodology. Critical for cross-platform audience deduplication and hybrid measurement. | Column applicable_platform_types (STRING) in audience.measurement_methodology',
    `audience_metric_types` STRING COMMENT 'Comma-separated list of audience metrics that this methodology can produce (e.g., GRP, TRP, HUT, PUT, reach, frequency, share, Nielsen_rating, TSR, CPRP). Governs which KPIs can be reported using data collected under this methodology. GRP (Gross Rating Point), TRP (Target Rating Point), HUT (Homes Using Television), PUT (Persons Using Television), TSR (Time Spent Reading/Viewing), CPRP (Cost Per Rating Point). | Column audience_metric_types (STRING) in audience.measurement_methodology',
    `consent_mechanism_required` STRING COMMENT 'The type of audience consent mechanism required for data collection under this methodology: opt_in (explicit consent required before data collection), opt_out (data collected unless individual opts out), panel_agreement (panelists sign participation agreement), no_consent_required (census/aggregate data with no individual tracking), or mixed. Governs GDPR, CCPA, and COPPA compliance posture. | Column consent_mechanism_required (STRING) in audience.measurement_methodology. Valid values are `opt_in|opt_out|panel_agreement|no_consent_required|mixed`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.measurement_methodology',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this measurement methodology record was first created in the Silver Layer data product. Used for data lineage, audit trail, and change management tracking. | Column created_timestamp (TIMESTAMP) in audience.measurement_methodology',
    `cross_platform_capable` BOOLEAN COMMENT 'Indicates whether this methodology supports cross-platform audience deduplication and unified reach/frequency reporting across linear TV, OTT (Over-The-Top), digital, and streaming platforms. Cross-platform capability is required for total audience measurement (TAM) reporting and advanced advertising guarantees. | Column cross_platform_capable (BOOLEAN) in audience.measurement_methodology',
    `currency_standard` STRING COMMENT 'The audience measurement currency standard supported by this methodology, defining the viewing window used for commercial ratings: C3 (average commercial ratings including 3 days of DVR playback), C7 (7-day DVR playback), C35 (35-day), live_plus_same_day, live_only, or custom. The currency standard is the contractual basis for ad sales guarantees and makegood calculations in upfront and scatter markets. | Column currency_standard (STRING) in audience.measurement_methodology. Valid values are `C3|C7|C35|live_plus_same_day|live_only|custom`',
    `data_collection_mechanism` STRING COMMENT 'The specific technical mechanism by which audience exposure data is collected: PPM device (Portable People Meter worn by panelists), diary form (paper or electronic self-report), STB return path (Set-Top Box return-path data), ACR fingerprint (Automatic Content Recognition audio/video fingerprinting), SDK telemetry (streaming app software development kit), pixel tracking (web/app pixel), or hybrid combination. Determines data fidelity and applicable use cases. [ENUM-REF-CANDIDATE: ppm_device|diary_form|stb_return_path|acr_fingerprint|sdk_telemetry|pixel_tracking|hybrid — 7 candidates stripped; promote to reference product] | Column data_collection_mechanism (STRING) in audience.measurement_methodology',
    `data_retention_days` STRING COMMENT 'The maximum number of days that raw audience measurement data collected under this methodology may be retained, as governed by privacy regulations (GDPR, CCPA) and MRC audit requirements. After this period, data must be anonymized or deleted. Drives data lifecycle management in the lakehouse. | Column data_retention_days (INT) in audience.measurement_methodology',
    `daypart_applicability` STRING COMMENT 'Comma-separated list of broadcast dayparts for which this methodology produces valid audience estimates (e.g., early_morning, daytime, early_fringe, prime_time, late_news, overnight). Daypart is a standard time segment of the broadcast day used in ad scheduling and CPM pricing. Some methodologies may have reduced reliability in overnight or early morning dayparts. | Column daypart_applicability (STRING) in audience.measurement_methodology',
    `deduplication_method` STRING COMMENT 'The method used to deduplicate audience reach across platforms or devices when this methodology is applied in cross-platform measurement: probabilistic (statistical modeling), deterministic (identity-matched), hybrid (combination), or none (single-platform only). Affects reported unique reach figures and frequency calculations. | Column deduplication_method (STRING) in audience.measurement_methodology. Valid values are `probabilistic|deterministic|hybrid|none`',
    `demographic_granularity` STRING COMMENT 'Describes the level of demographic segmentation this methodology supports (e.g., age_sex_only, age_sex_income, full_psychographic, household_level_only). Determines which audience segments can be reported for ad targeting, TRP calculations, and upfront sales guarantees. | Column demographic_granularity (STRING) in audience.measurement_methodology',
    `effective_from_date` DATE COMMENT 'The date from which this measurement methodology became or becomes valid for use in audience measurement, ratings reporting, and ad sales guarantees. Supports temporal validity tracking for methodology versioning and historical ratings restatement. | Column effective_from_date (DATE) in audience.measurement_methodology',
    `effective_until_date` DATE COMMENT 'The date on which this measurement methodology ceases to be valid for new audience measurement records. Null indicates the methodology is currently open-ended and active. Used to enforce temporal validity in ratings lookups and prevent application of deprecated methodologies to new viewership data. | Column effective_until_date (DATE) in audience.measurement_methodology',
    `geographic_coverage_level` STRING COMMENT 'The geographic scope at which this methodology provides valid audience measurement: national (US-wide), dma (Designated Market Area), regional, local (sub-DMA), international, or global. Determines applicability for local vs. national ad sales, retransmission consent negotiations, and blackout enforcement. | Column geographic_coverage_level (STRING) in audience.measurement_methodology. Valid values are `national|dma|regional|local|international|global`',
    `is_sweeps_applicable` BOOLEAN COMMENT 'Indicates whether this measurement methodology is used or enhanced during Nielsen Sweeps periods (February, May, July, November) — the intensive ratings measurement periods used to set local advertising rates. Diary methodology is exclusively sweeps-based in many markets; PPM operates year-round. | Column is_sweeps_applicable (BOOLEAN) in audience.measurement_methodology',
    `methodology_code` STRING COMMENT 'Short, externally-recognized alphanumeric code uniquely identifying the measurement methodology (e.g., NIELSEN_PPM, NIELSEN_DIARY, STB_DATA, ACR, STREAMING_TELEMETRY, HYBRID_XPLATFORM). Used as a stable business key across systems including Nielsen Media Research Platform and Adobe Experience Platform integrations. | Column methodology_code (STRING) in audience.measurement_methodology. Valid values are `^[A-Z0-9_]{2,30}$`',
    `methodology_description` STRING COMMENT 'Detailed narrative description of how the measurement methodology works, including data collection mechanism, panel recruitment approach, weighting procedures, and any known limitations. Used by ad sales teams, programming analysts, and regulatory compliance officers to understand how viewership and rating records are produced. | Column methodology_description (STRING) in audience.measurement_methodology',
    `methodology_name` STRING COMMENT 'Full human-readable name of the audience measurement methodology (e.g., Nielsen Portable People Meter, Nielsen Diary, Set-Top Box Data, Automatic Content Recognition, Streaming Platform Telemetry, Hybrid Cross-Platform Measurement). Used in reports, dashboards, and regulatory filings. | Column methodology_name (STRING) in audience.measurement_methodology',
    `methodology_status` STRING COMMENT 'Current lifecycle status of the measurement methodology within the organizations audience measurement framework. Active methodologies are used in current ratings and GRP/TRP reporting; deprecated or retired methodologies are retained for historical record interpretation; pilot methodologies are under evaluation for MRC accreditation. | Column methodology_status (STRING) in audience.measurement_methodology. Valid values are `active|deprecated|pilot|suspended|retired`',
    `methodology_type` STRING COMMENT 'Categorical classification of the measurement approach: passive (device-based passive capture such as PPM or STB), diary (self-reported viewer logs), census (full population streaming telemetry), hybrid (cross-platform combination), panel (statistically sampled panel), or acr (Automatic Content Recognition fingerprinting). Governs how ratings and GRP/TRP calculations are interpreted. | Column methodology_type (STRING) in audience.measurement_methodology. Valid values are `passive|diary|census|hybrid|panel|acr`',
    `mrc_accreditation_code` STRING COMMENT 'The official accreditation reference number issued by the Media Rating Council (MRC) for this measurement methodology. Used in regulatory filings, ad sales contracts, and audit documentation to reference the specific MRC accreditation certificate. | Column mrc_accreditation_code (STRING) in audience.measurement_methodology. Valid values are `^MRC-[A-Z0-9]{4,20}$`',
    `mrc_accreditation_date` DATE COMMENT 'The date on which the Media Rating Council (MRC) granted or last renewed accreditation for this measurement methodology. Used to track accreditation currency and trigger renewal workflows. | Column mrc_accreditation_date (DATE) in audience.measurement_methodology',
    `mrc_accreditation_expiry_date` DATE COMMENT 'The date on which the current MRC accreditation for this methodology expires. Methodologies with lapsed accreditation cannot be used in contractually binding audience guarantees for upfront or scatter market ad sales. Triggers compliance review and renewal workflows. | Column mrc_accreditation_expiry_date (DATE) in audience.measurement_methodology',
    `mrc_accreditation_status` STRING COMMENT 'Current accreditation status granted by the Media Rating Council (MRC) for this measurement methodology. MRC accreditation is the industry standard for validating audience measurement quality and is required for use in upfront and scatter market ad sales negotiations. Accredited methodologies carry full contractual weight; conditionally accredited methodologies may have usage restrictions. | Column mrc_accreditation_status (STRING) in audience.measurement_methodology. Valid values are `accredited|conditionally_accredited|not_accredited|under_review|suspended`',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, known limitations, special handling instructions, or contextual information about this measurement methodology. Examples include known panel biases, market-specific adjustments, or transition notes when migrating from one methodology version to another. | Column notes (STRING) in audience.measurement_methodology',
    `privacy_compliance_framework` STRING COMMENT 'Comma-separated list of privacy and data protection frameworks under which this methodologys data collection and processing is compliant (e.g., GDPR, CCPA, COPPA, TCPA). GDPR governs EU audience data; CCPA governs California viewer data; COPPA governs childrens content measurement. Required for regulatory reporting and data governance. | Column privacy_compliance_framework (STRING) in audience.measurement_methodology',
    `reporting_frequency` STRING COMMENT 'The cadence at which audience measurement data is reported using this methodology: overnight (daily ratings delivery), weekly, monthly, quarterly, or sweeps_only (data available only during Nielsen Sweeps measurement periods in February, May, July, and November). Governs scheduling of ad sales reporting and programming analysis cycles. | Column reporting_frequency (STRING) in audience.measurement_methodology. Valid values are `overnight|weekly|monthly|quarterly|sweeps_only`',
    `reporting_latency_hours` STRING COMMENT 'The typical number of hours between the audience exposure event and the availability of processed, reportable ratings data using this methodology. Nielsen PPM typically delivers overnight ratings within 24 hours; diary methodology may have 2–4 week latency. Critical for ad sales makegoods, scatter market decisions, and programming adjustments. | Column reporting_latency_hours (INT) in audience.measurement_methodology',
    `sample_size_minimum` STRING COMMENT 'The minimum number of panelists or measurement units required for this methodology to produce statistically valid audience estimates. Below this threshold, ratings data is considered unreliable and may be suppressed or flagged. Enforced per MRC accreditation requirements and Nielsen panel design standards. | Column sample_size_minimum (INT) in audience.measurement_methodology',
    `sample_size_target` STRING COMMENT 'The ideal or design target number of panelists or measurement units for this methodology to achieve the desired statistical confidence level and margin of error. Used in panel management and methodology performance monitoring against MRC accreditation benchmarks. | Column sample_size_target (INT) in audience.measurement_methodology',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.measurement_methodology',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this methodology definition originates (e.g., NIELSEN_MRP for Nielsen Media Research Platform, ADOBE_AEP for Adobe Experience Platform). Used for data lineage tracking and Silver Layer ingestion audit in the Databricks Lakehouse. | Column source_system_code (STRING) in audience.measurement_methodology. Valid values are `^[A-Z0-9_]{2,30}$`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.measurement_methodology',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this measurement methodology record was most recently modified in the Silver Layer data product. Used for incremental load detection, change data capture, and audit compliance. | Column updated_timestamp (TIMESTAMP) in audience.measurement_methodology',
    `vendor_methodology_version` STRING COMMENT 'The vendor-assigned version identifier for this measurement methodology (e.g., PPM v3.2, C3, C7, P2+ 2023). Version changes may affect historical comparability of ratings data and require restatement of audience guarantees. Critical for audit trails and makegood calculations. | Column vendor_methodology_version (STRING) in audience.measurement_methodology. Valid values are `^[A-Za-z0-9._-]{1,30}$`',
    `vendor_name` STRING COMMENT 'The name of the third-party vendor or research firm that operates or provides this measurement methodology (e.g., Nielsen, Comscore, Kantar, VideoAmp, iSpot.tv). Used for vendor management, contract tracking, and source system attribution in the Nielsen Media Research Platform integration. | Column vendor_name (STRING) in audience.measurement_methodology',
    CONSTRAINT pk_measurement_methodology PRIMARY KEY(`measurement_methodology_id`)
) COMMENT 'Reference master defining the audience measurement methodologies in use — Nielsen PPM (Portable People Meter), Nielsen Diary, Set-Top Box (STB) data, ACR (Automatic Content Recognition), streaming platform telemetry, and hybrid cross-platform measurement. Captures methodology code, description, applicable market types, sample size requirements, reporting latency, and accreditation body (MRC — Media Rating Council). Governs how each viewership and rating record is interpreted. | Unity Catalog table: media_broadcasting_ecm.audience.measurement_methodology Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`segment` (
    `segment_id` BIGINT COMMENT 'Unique surrogate identifier for the audience segment record in the Silver Layer lakehouse. Primary key for this master resource entity. | Column segment_id (BIGINT) in audience.segment',
    `coppa_declaration_id` BIGINT COMMENT 'Foreign key linking to compliance.coppa_declaration. Business justification: Audience segments targeting children must link to COPPA compliance declarations. Ensures parental consent mechanisms are in place before segment activation for advertising or analytics. | Column coppa_declaration_id (BIGINT) in compliance.segment',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.segment',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.segment',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.segment',
    `activation_status` STRING COMMENT 'Current lifecycle state of the segment governing whether it is available for use in ad targeting, campaign activation, or content personalization. draft indicates under construction; pending_review awaits compliance or data governance approval; active is live and deployable; inactive is suspended; archived is retired. | Column activation_status (STRING) in audience.segment. Valid values are `active|inactive|draft|archived|pending_review`',
    `aep_segment_code` STRING COMMENT 'The segment identifier as defined and managed within Adobe Experience Platform (AEP). Used for digital audience activation, personalization journeys, and cross-channel targeting. Enables synchronization between the internal audience_segment master record and the AEP segment definition for OTT and digital platforms. | Column aep_segment_code (STRING) in audience.segment',
    `age_range_max` STRING COMMENT 'Maximum age (inclusive) of the primary demographic target for this segment, expressed in years. Used with age_range_min to define the Nielsen demographic cell. A null value indicates an open-ended upper bound (e.g., 55+ segments). | Column age_range_max (INT) in audience.segment',
    `age_range_min` STRING COMMENT 'Minimum age (inclusive) of the primary demographic target for this segment, expressed in years. Used in conjunction with age_range_max to define the Nielsen demographic cell (e.g., 25 for the Adults 25-54 standard Nielsen demo). Null if the segment is not age-bounded. | Column age_range_min (INT) in audience.segment',
    `approved_by` STRING COMMENT 'Name or identifier of the data governance or compliance approver who authorized this segment for activation, particularly for segments involving sensitive demographic data, COPPA-restricted audiences, or GDPR-regulated EU audiences. Supports audit trail requirements. | Column approved_by (STRING) in audience.segment',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when this segment received formal data governance or compliance approval for activation. Distinct from created_timestamp — captures the approval lifecycle event. Required for GDPR accountability documentation and internal audit trails. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. | Column approved_timestamp (TIMESTAMP) in audience.segment',
    `segment_category` STRING COMMENT 'Business-facing category grouping segments for portfolio management and reporting (e.g., Ad Targeting, Programming Strategy, Content Personalization, Subscriber Retention, Regulatory Reporting). Enables segment library organization in Salesforce Media Cloud and Adobe AEP. [ENUM-REF-CANDIDATE: ad_targeting|programming_strategy|content_personalization|subscriber_retention|regulatory_reporting|audience_research — promote to reference product] | Column segment_category (STRING) in audience.segment',
    `segment_code` STRING COMMENT 'Externally-known, human-readable business identifier for the segment used across systems such as Adobe Experience Platform (AEP), Nielsen, and Salesforce Media Cloud. Serves as the canonical cross-system reference code (e.g., SEG-DEMO-F25-54-OTT). | Column segment_code (STRING) in audience.segment. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `content_genre_affinity` STRING COMMENT 'Primary content genre(s) this segment shows strong viewership affinity toward, used for programming strategy alignment and contextual ad targeting (e.g., drama,sports,news). Sourced from Nielsen viewing behavior data or Adobe AEP content interaction signals. Informs content acquisition decisions and ad pod placement strategy. | Column content_genre_affinity (STRING) in audience.segment',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.segment',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this audience segment record was first created in the system. Serves as the audit creation timestamp for data lineage, governance, and Silver Layer ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. | Column created_timestamp (TIMESTAMP) in audience.segment',
    `data_source` STRING COMMENT 'Identifies the primary data origin used to construct the segment. nielsen indicates Nielsen Media Research Platform ratings and demographic data; adobe_aep indicates Adobe Experience Platform behavioral profiles; first_party indicates proprietary subscriber or registration data; third_party indicates licensed external data; hybrid indicates a combination of multiple sources. | Column data_source (STRING) in audience.segment. Valid values are `nielsen|adobe_aep|first_party|third_party|hybrid`',
    `daypart_applicability` STRING COMMENT 'Broadcast daypart(s) for which this segment is most relevant or has been validated, expressed as a comma-delimited list of standard daypart labels (e.g., primetime,late_night). Daypart is a standard media-buying time segment of the broadcast day used in ad scheduling and upfront sales. [ENUM-REF-CANDIDATE: early_morning|daytime|early_fringe|primetime|late_news|late_night|overnight — promote to reference product] | Column daypart_applicability (STRING) in audience.segment',
    `definition_logic` STRING COMMENT 'The rule-based or SQL/JSON expression that defines segment membership criteria as implemented in Adobe AEP or Nielsen. Captures the inclusion/exclusion logic (e.g., age range, viewing frequency thresholds, content genre affinity, platform usage) used to qualify audience members into this segment. | Column definition_logic (STRING) in audience.segment',
    `segment_description` STRING COMMENT 'Detailed narrative description of the segments business purpose, defining criteria, and intended use cases. Provides context for ad sales teams, programmers, and data analysts on what the segment represents and how it should be applied. | Column segment_description (STRING) in audience.segment',
    `effective_from` DATE COMMENT 'The date from which this segment definition is considered valid and available for business use. Segments may be pre-built ahead of upfront sales seasons or campaign launches. Enables temporal validity management for segment versioning and historical reporting. | Column effective_from (DATE) in audience.segment',
    `effective_until` DATE COMMENT 'The date after which this segment definition is no longer valid for new activations. Null indicates an open-ended segment with no planned expiry. Used to manage seasonal segments (e.g., sweeps-period segments), campaign-specific segments, and segments tied to expiring data licensing agreements. | Column effective_until (DATE) in audience.segment',
    `estimated_reach` BIGINT COMMENT 'Estimated number of unique individuals (persons or households) who qualify for this segment at the time of last refresh. Reach is a core Nielsen and IAB metric used in ad sales proposals, GRP/TRP calculations, and CPM pricing. Distinct from impressions — counts unique audience members, not exposures. | Column estimated_reach (BIGINT) in audience.segment',
    `estimated_reach_unit` STRING COMMENT 'Unit of measurement for the estimated_reach figure. persons aligns with Nielsen PUT (Persons Using Television) methodology; households aligns with HUT (Homes Using Television); devices applies to digital/OTT platform segments measured by device-level identity. | Column estimated_reach_unit (STRING) in audience.segment. Valid values are `persons|households|devices`',
    `gender_target` STRING COMMENT 'Gender composition target for the segment as defined in Nielsen demographic cells and ad sales targeting parameters. all indicates gender-neutral targeting. Used in GRP (Gross Rating Point) and TRP (Target Rating Point) calculations for ad campaign planning. | Column gender_target (STRING) in audience.segment. Valid values are `male|female|all|non_binary`',
    `grp_index` DECIMAL(18,2) COMMENT 'The GRP (Gross Rating Point) index value representing this segments relative audience weight as a percentage of the total universe. GRP is a fundamental media planning metric equal to Reach × Frequency. Used in upfront and scatter market ad sales to price inventory and measure campaign delivery against this segment. | Column grp_index (DECIMAL(10,4)) in audience.segment',
    `hut_put_basis` STRING COMMENT 'Indicates whether the segments reach and rating metrics are calculated on a HUT (Homes Using Television) or PUT (Persons Using Television) basis. HUT is household-level measurement; PUT is person-level. This distinction governs how GRP/TRP values are interpreted and how the segment is applied in Nielsen-based ad sales planning. | Column hut_put_basis (STRING) in audience.segment. Valid values are `hut|put`',
    `income_bracket` STRING COMMENT 'Household income tier associated with the segments demographic composition, used in premium ad targeting and CPM (Cost Per Mille) pricing. Expressed as a standardized range label (e.g., $75K-$100K HHI, $100K+ HHI). Sourced from Nielsen MRI-Simmons or first-party subscriber data. [ENUM-REF-CANDIDATE: under_25k|25k_50k|50k_75k|75k_100k|100k_150k|150k_plus — promote to reference product] | Column income_bracket (STRING) in audience.segment',
    `is_dai_eligible` BOOLEAN COMMENT 'Indicates whether this segment is approved and technically configured for use in DAI (Dynamic Ad Insertion) workflows on OTT and streaming platforms. DAI-eligible segments can be activated in real-time ad decisioning systems integrated with Akamai CDN and programmatic ad servers for addressable advertising. | Column is_dai_eligible (BOOLEAN) in audience.segment',
    `is_sweeps_validated` BOOLEAN COMMENT 'Indicates whether this segments reach and demographic composition estimates have been validated using Nielsen Sweeps period data (the intensive ratings measurement periods in February, May, July, and November). Sweeps-validated segments carry higher confidence for upfront ad sales commitments and programming decisions. | Column is_sweeps_validated (BOOLEAN) in audience.segment',
    `last_refresh_timestamp` TIMESTAMP COMMENT 'The date and time when the segment membership, reach estimates, and demographic composition were last recalculated from source data. Used to assess data freshness for ad sales proposals and campaign activation. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. | Column last_refresh_timestamp (TIMESTAMP) in audience.segment',
    `modified_timestamp` TIMESTAMP COMMENT 'The date and time when this audience segment record was last updated. Tracks changes to segment definition, status, reach estimates, or compliance flags. Used for change data capture (CDC) in the Databricks Silver Layer pipeline and audit trail maintenance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX. | Column modified_timestamp (TIMESTAMP) in audience.segment',
    `segment_name` STRING COMMENT 'Human-readable display name for the audience segment as it appears in ad sales proposals, programming strategy decks, and campaign targeting UIs (e.g., Women 25-54 OTT Heavy Viewers). Corresponds to the segment label in Adobe AEP and Salesforce Media Cloud. | Column segment_name (STRING) in audience.segment',
    `nielsen_segment_code` STRING COMMENT 'The corresponding segment or audience cell identifier within the Nielsen Media Research Platform. Enables direct linkage to Nielsen ratings data, GRP/TRP delivery reports, and demographic reach/frequency outputs. Used for reconciliation between internal segment definitions and Nielsen-measured audience delivery. | Column nielsen_segment_code (STRING) in audience.segment',
    `notes` STRING COMMENT 'Free-text field for additional business context, caveats, or operational notes about the segment that do not fit structured fields. Examples include data quality warnings, known limitations of the definition logic, special handling instructions for ad sales, or notes on upcoming segment retirement. | Column notes (STRING) in audience.segment',
    `owner_team` STRING COMMENT 'The business team or department that owns and is accountable for this segments definition, quality, and lifecycle management (e.g., Ad Sales Research, Audience Analytics, Programming Strategy, Digital Marketing). Used for data governance, access control, and segment portfolio management. | Column owner_team (STRING) in audience.segment',
    `platform_applicability` STRING COMMENT 'Comma-delimited list of distribution platforms for which this segment is valid and activated (e.g., linear,ott,avod,svod,fast). Governs where the segment can be applied for ad targeting or content personalization across Linear, OTT (Over-The-Top), AVOD (Advertising-Supported Video On Demand), SVOD (Subscription Video On Demand), and FAST (Free Ad-Supported Streaming Television) channels. [ENUM-REF-CANDIDATE: linear|ott|avod|svod|tvod|fast|social|digital_display — promote to reference product] | Column platform_applicability (STRING) in audience.segment',
    `programmatic_targetable_flag` BOOLEAN COMMENT 'Flag indicating segment is targetable in programmatic',
    `refresh_frequency` STRING COMMENT 'How frequently the segment membership and reach estimates are recalculated and updated from source systems (Nielsen, Adobe AEP, or first-party data). Governs data freshness SLAs for ad targeting activation. real_time applies to DAI-eligible programmatic segments; daily is standard for digital; weekly/monthly for Nielsen-based linear segments. | Column refresh_frequency (STRING) in audience.segment. Valid values are `real_time|daily|weekly|monthly|quarterly|on_demand`',
    `segment_type` STRING COMMENT 'Classification of the segment by the primary methodology used to define it. Demographic segments are built on age/gender/HUT criteria; behavioral on viewing patterns; psychographic on interests/attitudes; contextual on content affinity; lookalike on modeled similarity to a seed audience. | Column segment_type (STRING) in audience.segment. Valid values are `demographic|behavioral|psychographic|contextual|lookalike`',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.segment',
    `trp_index` DECIMAL(18,2) COMMENT 'The TRP (Target Rating Point) index value representing this segments rating within its specific target demographic universe. TRP is the targeted equivalent of GRP, measuring delivery efficiency against the defined demographic cell. Critical for ad sales pricing, makegoods calculations, and CPRP (Cost Per Rating Point) negotiations. | Column trp_index (DECIMAL(10,4)) in audience.segment',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.segment',
    `version_number` STRING COMMENT 'Monotonically incrementing version counter for the segment definition. Incremented each time the segments definition logic, demographic criteria, or platform applicability is materially changed. Enables segment versioning for historical campaign attribution — ad campaigns reference the segment version active at time of booking. | Column version_number (INT) in audience.segment',
    CONSTRAINT pk_segment PRIMARY KEY(`segment_id`)
) COMMENT 'Master record for a defined, reusable audience segment built from demographic, behavioral, and psychographic criteria for use in ad targeting, programming strategy, and content personalization. Captures segment name, definition logic, estimated size, demographic composition, platform applicability, activation status, and data source (Nielsen, Adobe AEP, first-party). Distinct from demographic_segment (which is a reference classification) — this is an operationally managed, business-owned targeting segment. | Unity Catalog table: media_broadcasting_ecm.audience.segment Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`cross_platform_measurement` (
    `cross_platform_measurement_id` BIGINT COMMENT 'Unique surrogate identifier for each cross-platform audience measurement record in the Silver layer lakehouse. Primary key for this transactional entity. | Column cross_platform_measurement_id (BIGINT) in audience.cross_platform_measurement',
    `sales_campaign_id` BIGINT COMMENT 'Reference to the advertising campaign flight for which this cross-platform measurement is being reported. Enables audience currency reconciliation for converged TV buying. Nullable when measurement is content-centric rather than campaign-centric. | Column campaign_id (BIGINT) in sales.cross_platform_measurement',
    `content_rating_id` BIGINT COMMENT 'Foreign key linking to compliance.content_rating. Business justification: Cross-platform metrics require rating context for regulatory reporting (childrens programming hours) and advertiser suitability verification across linear and streaming delivery. | Column compliance_content_rating_id (BIGINT) in compliance.cross_platform_measurement',
    `title_id` BIGINT COMMENT 'Reference to the content title or program for which this cross-platform audience measurement is recorded. Links to the content master data product in the Content domain. | Column content_title_id (BIGINT) in content.cross_platform_measurement',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Cross-platform metrics attribute audience delivery across linear/digital to content-producing cost centers. Content ROI analysis and budget allocation decisions require linking multi-platform performa | Column cost_center_id (BIGINT) in finance.cross_platform_measurement',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to audience.demographic_segment. Business justification: Cross-platform measurements target specific demographic segments for deduplicated reach calculations. The target_demographic string should be replaced with FK to demographic_segment for consistency wi | Column demographic_segment_id (BIGINT) in audience.cross_platform_measurement',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to audience.market_coverage. Business justification: Cross-platform measurements are aggregated by DMA/market. The geographic_market_code should be replaced with FK to market_coverage for consistency with nielsen_rating and other measurement products. | Column market_coverage_id (BIGINT) in audience.cross_platform_measurement',
    `employee_id` BIGINT COMMENT 'Foreign key linking to workforce.employee. Business justification: Cross-platform measurement requires specialized analysts to perform deduplication, validate MRC-accredited methodologies, reconcile linear/OTT/MVPD impressions, and certify total audience metrics. Ana | Column measurement_analyst_employee_id (BIGINT) in workforce.cross_platform_measurement',
    `measurement_methodology_id` BIGINT COMMENT 'Foreign key linking to audience.measurement_methodology. Business justification: Cross-platform measurements use specific methodologies for deduplication and aggregation. The measurement_methodology string and measurement_vendor should be replaced with FK to measurement_methodolog | Column measurement_methodology_id (BIGINT) in audience.cross_platform_measurement',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.cross_platform_measurement',
    `opportunity_id` BIGINT COMMENT 'Foreign key linking to sales.opportunity. Business justification: Cross-platform measurement is a key differentiator in modern media sales, directly referenced when pitching multi-platform opportunities. Sales teams use cross-platform reach data to justify premium p | Column opportunity_id (BIGINT) in sales.cross_platform_measurement',
    `partner_id` BIGINT COMMENT 'Foreign key linking to partner.partner_partner. Business justification: Cross-platform measurement must attribute audience delivery to specific distribution/carriage partners for revenue share calculations and partner performance evaluation. Essential for multi-platform p | Column partner_id (BIGINT) in partner.cross_platform_measurement',
    `production_episode_id` BIGINT COMMENT 'Foreign key linking to production.production_episode. Business justification: Episode-level cross-platform measurement is required for total audience delivery verification, especially for time-shifted viewing and multi-platform distribution. Essential for C3/C7 ratings and adve | Column production_episode_id (BIGINT) in production.cross_platform_measurement',
    `project_id` BIGINT COMMENT 'Foreign key linking to production.project. Business justification: Cross-platform measurement aggregates linear TV + streaming + social video performance for specific production projects. Required for total audience reporting, C3/C7 ratings, and advertiser delivery v | Column production_project_id (BIGINT) in production.cross_platform_measurement',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Cross-platform audience drives profit center revenue allocation across distribution channels. Segment reporting for investors and internal management reviews require tying total audience delivery to n | Column profit_center_id (BIGINT) in finance.cross_platform_measurement',
    `sweeps_period_id` BIGINT COMMENT 'Foreign key linking to audience.sweeps_period. Business justification: Cross-platform measurements during sweeps periods are critical for upfront negotiations and guarantee reconciliation. The is_sweeps_period flag indicates relevance, but the specific sweeps period shou | Column sweeps_period_id (BIGINT) in audience.cross_platform_measurement',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.cross_platform_measurement',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.cross_platform_measurement',
    `audience_share` DECIMAL(18,2) COMMENT 'Percentage of the total viewing audience (HUT or PUT) that was watching this specific content or channel during the measurement period. Calculated as the program rating divided by HUT or PUT. Key programming performance indicator. | Column audience_share (DECIMAL(8,4)) in audience.cross_platform_measurement',
    `average_frequency` DECIMAL(18,2) COMMENT 'Average number of times a unique individual in the deduplicated reach was exposed to the content or campaign across all platforms within the measurement period. Calculated as total impressions divided by deduplicated reach. | Column average_frequency (DECIMAL(8,4)) in audience.cross_platform_measurement',
    `co_viewing_adjustment_factor` DECIMAL(18,2) COMMENT 'Multiplicative adjustment factor applied to account for co-viewing behavior (multiple persons watching on a single device/screen), particularly relevant for connected TV and OTT platforms. Values greater than 1.0 indicate upward adjustment for co-viewing. Sourced from Nielsen co-viewing methodology. | Column co_viewing_adjustment_factor (DECIMAL(8,6)) in audience.cross_platform_measurement',
    `content_genre` STRING COMMENT 'Genre classification of the content title being measured (e.g., Drama, News, Sports, Reality, Comedy, Documentary). Used for audience segmentation analysis and programming strategy reporting. [ENUM-REF-CANDIDATE: drama|news|sports|reality|comedy|documentary|talk|game_show|animation|other — promote to reference product] | Column content_genre (STRING) in audience.cross_platform_measurement',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.cross_platform_measurement',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this cross-platform measurement record was first ingested into the Silver layer lakehouse. | Column created_timestamp (TIMESTAMP) in audience.cross_platform_measurement',
    `cross_platform_grp` DECIMAL(18,2) COMMENT 'Gross Rating Point (GRP) calculated across all measured platforms, representing the sum of ratings for all platform exposures within the target universe. Equals total impressions divided by the target universe population, multiplied by 100. Primary audience currency for converged TV ad buying. | Column cross_platform_grp (DECIMAL(10,4)) in audience.cross_platform_measurement',
    `cross_platform_trp` DECIMAL(18,2) COMMENT 'Target Rating Point (TRP) calculated across all measured platforms for the specified target demographic segment. Measures GRP within the defined target audience, used for demographic-specific ad buying and campaign performance evaluation. | Column cross_platform_trp (DECIMAL(10,4)) in audience.cross_platform_measurement',
    `currency_version` STRING COMMENT 'Version identifier of the audience measurement currency standard applied to this record (e.g., Nielsen ONE v2.1, Comscore Campaign Ratings v3.0). Supports multi-currency and currency transition tracking as the industry evolves from legacy Nielsen C3/C7 to cross-platform currencies. | Column currency_version (STRING) in audience.cross_platform_measurement',
    `data_source_systems` STRING COMMENT 'Pipe-delimited list of operational source systems that contributed data to this cross-platform measurement record (e.g., Nielsen Media Research Platform|Adobe Experience Platform). Supports data lineage, audit, and methodology transparency requirements. | Column data_source_systems (STRING) in audience.cross_platform_measurement',
    `daypart_code` STRING COMMENT 'Broadcast daypart classification for the measurement period, representing the time segment of the broadcast day. [ENUM-REF-CANDIDATE: EAM|AM|DAYTIME|EARLY_FRINGE|PRIME|LATE_FRINGE|OVERNIGHT — promote to reference product if additional dayparts are required] | Column daypart_code (STRING) in audience.cross_platform_measurement',
    `deduplicated_reach` BIGINT COMMENT 'Total count of unique, unduplicated individuals (persons) who were exposed to the content or campaign across all measured platforms within the measurement period. Core audience currency metric for converged TV buying. Expressed as absolute person count. | Column deduplicated_reach (BIGINT) in audience.cross_platform_measurement',
    `distribution_type` STRING COMMENT 'Primary distribution model classification for the content being measured: linear for traditional scheduled broadcast; vod for generic on-demand; svod for subscription streaming; avod for ad-supported streaming; tvod for transactional on-demand; fast for free ad-supported streaming TV; social for social video platforms. [ENUM-REF-CANDIDATE: linear|vod|svod|avod|tvod|fast|social — 7 candidates stripped; promote to reference product] | Column distribution_type (STRING) in audience.cross_platform_measurement',
    `fast_channel_impressions` BIGINT COMMENT 'Audience impressions attributed to Free Ad-Supported Streaming Television (FAST) channels within the measurement period. Represents the growing ad-supported streaming audience segment. | Column fast_channel_impressions (BIGINT) in audience.cross_platform_measurement',
    `hut_rating` DECIMAL(18,2) COMMENT 'Homes Using Television (HUT) rating for the measurement period, representing the percentage of all television households with at least one TV set in use during the measured time period. Used for share calculations and programming decisions. | Column hut_rating (DECIMAL(8,4)) in audience.cross_platform_measurement',
    `is_data_suppressed` BOOLEAN COMMENT 'Indicates whether this measurement record has been suppressed from reporting due to insufficient panel sample size, MRC minimum reporting thresholds, or privacy regulations (GDPR/CCPA). Suppressed records are retained for audit but excluded from audience currency reporting. | Column is_data_suppressed (BOOLEAN) in audience.cross_platform_measurement',
    `is_mrc_accredited` BOOLEAN COMMENT 'Indicates whether this measurement was produced using a methodology that holds current Media Rating Council (MRC) accreditation for cross-platform measurement. MRC accreditation is required for use as official audience currency in upfront and scatter market ad transactions. | Column is_mrc_accredited (BOOLEAN) in audience.cross_platform_measurement',
    `is_sweeps_period` BOOLEAN COMMENT 'Indicates whether this measurement falls within a Nielsen sweeps period (February, May, July, November), which represents an intensive ratings measurement window used for programming and ad rate decisions. | Column is_sweeps_period (BOOLEAN) in audience.cross_platform_measurement',
    `isan_code` STRING COMMENT 'International Standard Audiovisual Number (ISAN) for the content title being measured, providing a globally unique, persistent identifier for the audiovisual work. Enables cross-system content identification and rights reconciliation. | Column isan_code (STRING) in audience.cross_platform_measurement. Valid values are `^ISAN [0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `linear_impressions` BIGINT COMMENT 'Audience impressions attributed to traditional linear broadcast television (over-the-air, cable, satellite) within the measurement period. Component of the platform-level audience breakdown. | Column linear_impressions (BIGINT) in audience.cross_platform_measurement',
    `measurement_period_end` DATE COMMENT 'The last date of the audience measurement observation window, aligned to the content airing schedule or campaign flight end. | Column measurement_period_end (DATE) in audience.cross_platform_measurement',
    `measurement_period_start` DATE COMMENT 'The first date of the audience measurement observation window, aligned to the content airing schedule or campaign flight start. Used for sweeps period identification and daypart analysis. | Column measurement_period_start (DATE) in audience.cross_platform_measurement',
    `measurement_reference_number` STRING COMMENT 'Externally-known business identifier for this cross-platform measurement record, used in reporting, ad sales proposals, and audience currency reconciliation. Sourced from Nielsen Media Research Platform or internal measurement workflow. | Column measurement_reference_number (STRING) in audience.cross_platform_measurement',
    `measurement_status` STRING COMMENT 'Current lifecycle state of the cross-platform measurement record. draft indicates data is being assembled; preliminary indicates initial estimate released; certified indicates MRC-audited final figure; revised indicates a post-certification correction; archived indicates superseded by a newer measurement. | Column measurement_status (STRING) in audience.cross_platform_measurement. Valid values are `draft|preliminary|certified|revised|archived`',
    `measurement_timestamp` TIMESTAMP COMMENT 'The principal real-world timestamp representing when the audience measurement observation period was captured or the measurement run was executed. Distinct from record audit timestamps. | Column measurement_timestamp (TIMESTAMP) in audience.cross_platform_measurement',
    `mvpd_impressions` BIGINT COMMENT 'Audience impressions attributed to Multichannel Video Programming Distributor (MVPD) and virtual MVPD (vMVPD) platforms, including cable, satellite, and virtual pay-TV providers within the measurement period. | Column mvpd_impressions (BIGINT) in audience.cross_platform_measurement',
    `nielsen_rating` DECIMAL(18,2) COMMENT 'The Nielsen Rating for the content or program within the measurement period, representing the percentage of all television households or persons in the universe tuned to the program. The foundational audience currency metric for linear broadcast. | Column nielsen_rating (DECIMAL(8,4)) in audience.cross_platform_measurement',
    `ott_streaming_impressions` BIGINT COMMENT 'Audience impressions attributed to Over-The-Top (OTT) and Subscription Video On Demand (SVOD) streaming platforms within the measurement period. Includes authenticated streaming on connected TV, mobile, and desktop devices. | Column ott_streaming_impressions (BIGINT) in audience.cross_platform_measurement',
    `panel_sample_size` STRING COMMENT 'Number of panel households or persons in the Nielsen (or equivalent vendor) measurement panel that contributed to this cross-platform measurement. Indicates statistical reliability; low sample sizes may trigger data suppression per MRC minimum reporting standards. | Column panel_sample_size (INT) in audience.cross_platform_measurement',
    `put_rating` DECIMAL(18,2) COMMENT 'Persons Using Television (PUT) rating for the measurement period, representing the percentage of all persons in the universe who are watching television during the measured time period. Used for person-level audience share calculations. | Column put_rating (DECIMAL(8,4)) in audience.cross_platform_measurement',
    `social_video_impressions` BIGINT COMMENT 'Audience impressions attributed to social video platforms (e.g., YouTube, Facebook Video, TikTok, Instagram Reels) within the measurement period. Enables full cross-platform audience aggregation. | Column social_video_impressions (BIGINT) in audience.cross_platform_measurement',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.cross_platform_measurement',
    `target_universe_size` BIGINT COMMENT 'The estimated total population size of the target demographic universe used as the denominator for GRP and TRP calculations. Sourced from Nielsen universe estimates updated annually. | Column target_universe_size (BIGINT) in audience.cross_platform_measurement',
    `total_impressions` BIGINT COMMENT 'Total number of audience exposures (impressions) across all platforms within the measurement period, including duplicate exposures across platforms. Used for CPM-based advertising currency and GRP calculation inputs. | Column total_impressions (BIGINT) in audience.cross_platform_measurement',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.cross_platform_measurement',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this cross-platform measurement record was last modified, supporting data lineage and revision tracking. | Column updated_timestamp (TIMESTAMP) in audience.cross_platform_measurement',
    CONSTRAINT pk_cross_platform_measurement PRIMARY KEY(`cross_platform_measurement_id`)
) COMMENT 'Transactional record aggregating deduplicated audience measurement across linear broadcast, OTT/SVOD streaming, MVPD/vMVPD, FAST channels, and social video platforms for a specific content title or campaign flight. Captures deduplicated reach, total impressions, platform-level audience breakdown, co-viewing adjustment factor, cross-platform GRP/TRP, and big data + panel fusion methodology indicators. Aligns with Nielsen ONE, Comscore, and MRC cross-platform measurement standards. Enables unified audience currency reporting for converged TV buying. | Unity Catalog table: media_broadcasting_ecm.audience.cross_platform_measurement Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`market_distribution_agreement` (
    `market_distribution_agreement_id` BIGINT COMMENT 'Unique surrogate identifier for this market-partner distribution agreement record | Column market_distribution_agreement_id (BIGINT) in audience.market_distribution_agreement',
    `market_coverage_id` BIGINT COMMENT 'Foreign key linking to the DMA/market coverage area where this distribution agreement applies | Column market_coverage_id (BIGINT) in audience.market_distribution_agreement',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.market_distribution_agreement',
    `partner_id` BIGINT COMMENT 'Foreign key linking to the distribution partner (MVPD, vMVPD, affiliate, syndicator) party to this agreement | Column partner_id (BIGINT) in partner.market_distribution_agreement',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.market_distribution_agreement',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.market_distribution_agreement',
    `agreement_status` STRING COMMENT 'Current lifecycle status of this market-partner distribution agreement. | Column agreement_status (STRING) in audience.market_distribution_agreement',
    `carriage_fee_per_subscriber` DECIMAL(18,2) COMMENT 'Negotiated monthly or annual fee paid per subscriber for carriage rights in this specific market. This rate varies by market size, partner type, and competitive dynamics. | Column carriage_fee_per_subscriber (DECIMAL(10,4)) in audience.market_distribution_agreement',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.market_distribution_agreement',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when this market distribution agreement record was created. | Column created_timestamp (TIMESTAMP) in audience.market_distribution_agreement',
    `effective_end_date` DATE COMMENT 'Date when this market-specific distribution agreement expires or terminates. Null indicates an evergreen or currently active agreement. | Column effective_end_date (DATE) in audience.market_distribution_agreement',
    `effective_start_date` DATE COMMENT 'Date when this market-specific distribution agreement becomes effective and carriage rights commence. | Column effective_start_date (DATE) in audience.market_distribution_agreement',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this distribution agreement grants exclusive carriage rights to the partner in this market, preventing competing distribution deals. | Column exclusivity_flag (BOOLEAN) in audience.market_distribution_agreement',
    `last_renewal_date` DATE COMMENT 'Date when this market-specific agreement was most recently renewed or renegotiated. | Column last_renewal_date (DATE) in audience.market_distribution_agreement',
    `must_carry_status` STRING COMMENT 'FCC regulatory classification for this market-partner carriage relationship: must-carry obligation, retransmission consent negotiation, or not applicable. | Column must_carry_status (STRING) in audience.market_distribution_agreement',
    `next_negotiation_date` DATE COMMENT 'Scheduled date for the next contract renegotiation or renewal discussion for this market-partner relationship. | Column next_negotiation_date (DATE) in audience.market_distribution_agreement',
    `penetration_rate` DECIMAL(18,2) COMMENT 'Percentage of total TV households in the market that subscribe to this partners service. Calculated as subscriber_count divided by market TV household universe. | Column penetration_rate (DECIMAL(8,4)) in audience.market_distribution_agreement',
    `performance_tier` STRING COMMENT 'Classification of the partners performance in this specific market based on subscriber growth, payment compliance, and audience delivery metrics. | Column performance_tier (STRING) in audience.market_distribution_agreement',
    `retransmission_consent_granted` BOOLEAN COMMENT 'Indicates whether retransmission consent has been granted to this partner for broadcast signals in this market, per FCC regulations. | Column retransmission_consent_granted (BOOLEAN) in audience.market_distribution_agreement',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.market_distribution_agreement',
    `subscriber_count` BIGINT COMMENT 'Current number of subscribers the partner serves in this market. Used to calculate total carriage fees and assess market penetration. | Column subscriber_count (BIGINT) in audience.market_distribution_agreement',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.market_distribution_agreement',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this market distribution agreement record was last modified. | Column updated_timestamp (TIMESTAMP) in audience.market_distribution_agreement',
    CONSTRAINT pk_market_distribution_agreement PRIMARY KEY(`market_distribution_agreement_id`)
) COMMENT 'This association product represents the contractual distribution agreement between a market coverage area and a distribution partner. It captures market-specific carriage terms, subscriber economics, and territorial rights that exist only in the context of this market-partner relationship. Each record links one DMA/market to one distribution partner with commercial terms, performance metrics, and exclusivity provisions that vary by market-partner combination.. Existence Justification: Distribution partners (MVPDs, vMVPDs, affiliates, syndicators) operate across multiple geographic markets, each with market-specific carriage agreements, subscriber counts, and commercial terms. Conversely, each DMA/market has multiple distribution partners competing or coexisting with different penetration rates, carriage fees, and exclusivity provisions. This is the operational foundation of territorial rights management and market-based distribution economics in media broadcasting. | Unity Catalog table: media_broadcasting_ecm.audience.market_distribution_agreement Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`talent_demographic_appeal` (
    `talent_demographic_appeal_id` BIGINT COMMENT 'Unique surrogate identifier for each talent demographic appeal measurement record. Primary key for the association. | Column talent_demographic_appeal_id (BIGINT) in audience.talent_demographic_appeal',
    `demographic_segment_id` BIGINT COMMENT 'Foreign key linking to the demographic segment for which this appeal measurement applies | Column demographic_segment_id (BIGINT) in audience.talent_demographic_appeal',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.talent_demographic_appeal',
    `talent_profile_id` BIGINT COMMENT 'Foreign key linking to the talent profile being measured for demographic appeal | Column talent_profile_id (BIGINT) in talent.talent_demographic_appeal',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.talent_demographic_appeal',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.talent_demographic_appeal',
    `appeal_index` DECIMAL(18,2) COMMENT 'Normalized appeal index score measuring the talents overall appeal within this specific demographic segment. Scale and methodology aligned with industry standards for talent appeal measurement. | Column appeal_index (DECIMAL(10,4)) in audience.talent_demographic_appeal',
    `awareness_percentage` DECIMAL(18,2) COMMENT 'Percentage of the demographic segment that is aware of or recognizes this talent. Key metric for talent reach and recognition within the target demographic. | Column awareness_percentage (DECIMAL(5,2)) in audience.talent_demographic_appeal',
    `casting_recommendation_flag` BOOLEAN COMMENT 'Indicates whether this talent is recommended for casting in content targeting this demographic segment based on appeal thresholds. Used by casting directors and programming teams. | Column casting_recommendation_flag (BOOLEAN) in audience.talent_demographic_appeal',
    `confidence_interval` DECIMAL(18,2) COMMENT 'Statistical confidence interval (margin of error) for the appeal metrics in this measurement, expressed as a percentage. Used to assess measurement precision. | Column confidence_interval (DECIMAL(5,2)) in audience.talent_demographic_appeal',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.talent_demographic_appeal',
    `favorability_rating` DECIMAL(18,2) COMMENT 'Favorability or likability rating of the talent among respondents in this demographic segment who are aware of the talent. Measures positive sentiment. | Column favorability_rating (DECIMAL(10,4)) in audience.talent_demographic_appeal',
    `measurement_date` DATE COMMENT 'The date when this appeal measurement was conducted or published. Critical for tracking appeal trends over time and ensuring measurement currency. | Column measurement_date (DATE) in audience.talent_demographic_appeal',
    `measurement_methodology` STRING COMMENT 'The research methodology used to measure this talents appeal within this demographic (e.g., Q_Score_Standard, Custom_Survey, Panel_Research). Ensures comparability and appropriate interpretation of metrics. | Column measurement_methodology (STRING) in audience.talent_demographic_appeal',
    `measurement_status` STRING COMMENT 'Lifecycle status of this appeal measurement record. Current measurements are used for active casting and programming decisions; Historical measurements are retained for trend analysis. | Column measurement_status (STRING) in audience.talent_demographic_appeal',
    `measurement_vendor` STRING COMMENT 'The research vendor or organization that conducted the appeal measurement (e.g., Marketing Evaluations Inc., Nielsen, custom internal research). Used for data provenance and methodology validation. | Column measurement_vendor (STRING) in audience.talent_demographic_appeal',
    `q_score` DECIMAL(18,2) COMMENT 'The Marketing Evaluations Q Score for this talent within this demographic segment. Measures familiarity and appeal, used industry-wide for talent valuation and casting decisions. | Column q_score (DECIMAL(10,4)) in audience.talent_demographic_appeal',
    `record_created_timestamp` TIMESTAMP COMMENT 'System timestamp when this talent demographic appeal record was created in the data platform. | Column record_created_timestamp (TIMESTAMP) in audience.talent_demographic_appeal',
    `record_updated_timestamp` TIMESTAMP COMMENT 'System timestamp when this talent demographic appeal record was last updated. | Column record_updated_timestamp (TIMESTAMP) in audience.talent_demographic_appeal',
    `sample_size` STRING COMMENT 'The number of respondents from this demographic segment included in the appeal measurement study. Used to assess statistical confidence and measurement reliability. | Column sample_size (INT) in audience.talent_demographic_appeal',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.talent_demographic_appeal',
    `trend_direction` STRING COMMENT 'The directional trend of this talents appeal within this demographic compared to prior measurements (Rising, Stable, Declining). Used for talent investment and booking strategy. | Column trend_direction (STRING) in audience.talent_demographic_appeal',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.talent_demographic_appeal',
    CONSTRAINT pk_talent_demographic_appeal PRIMARY KEY(`talent_demographic_appeal_id`)
) COMMENT 'This association product represents the measured appeal and awareness metrics of talent across specific demographic segments. It captures Q Score ratings, awareness percentages, favorability ratings, and appeal indices that exist only in the context of a specific talent-demographic combination. Each record links one talent_profile to one demographic_segment with measurement data used for casting decisions, talent booking, programming strategy, and advertising sales targeting. This is the operational system of record for talent appeal research used by programming, casting, and ad sales teams.. Existence Justification: In media broadcasting operations, talent appeal is measured across multiple demographic segments simultaneously (e.g., a host has different Q Scores for A18-49, W25-54, M18-34), and each demographic segment has appeal measurements for multiple talent profiles. Casting directors, programming strategists, and ad sales teams actively query and manage this appeal data to make talent booking decisions, programming placement, and advertising targeting decisions. This is operational audience research data, not an analytical correlation. | Unity Catalog table: media_broadcasting_ecm.audience.talent_demographic_appeal Integrates with Adobe Experience Platform (audience platform).';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`audience`.`segment_regulatory_compliance` (
    `segment_regulatory_compliance_id` BIGINT COMMENT 'Unique surrogate identifier for this segment-obligation compliance record. Primary key. | Column segment_regulatory_compliance_id (BIGINT) in audience.segment_regulatory_compliance',
    `measurement_source_ref_id` BIGINT COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column source_id (STRING) in audience.segment_regulatory_compliance',
    `segment_id` BIGINT COMMENT 'Foreign key to audience_segment. Part of the natural key. | Column audience_segment_id (BIGINT) in audience.segment_regulatory_compliance',
    `regulatory_obligation_id` BIGINT COMMENT 'Foreign key linking to the regulatory obligation that governs this segment | Column regulatory_obligation_id (BIGINT) in compliance.segment_regulatory_compliance',
    `_created_at` TIMESTAMP COMMENT 'Medallion lineage column for _created_at | Column _created_at (TIMESTAMP) in audience.segment_regulatory_compliance',
    `_updated_at` TIMESTAMP COMMENT 'Medallion lineage column for _updated_at | Column _updated_at (TIMESTAMP) in audience.segment_regulatory_compliance',
    `activation_date` DATE COMMENT 'Date when this audience segment was activated for use under this specific regulatory obligation. Represents when the segment was first deployed in campaigns subject to this regulation. | Column activation_date (DATE) in audience.segment_regulatory_compliance',
    `audit_findings` STRING COMMENT 'Summary of findings from the most recent compliance audit. Documents any violations, concerns, or confirmations of compliance. Used for audit trail and remediation tracking. | Column audit_findings (STRING) in audience.segment_regulatory_compliance',
    `ccpa_opt_out_honored` BOOLEAN COMMENT 'Indicates whether California Consumer Privacy Act (CCPA) opt-out signals are honored when activating this segment for California residents. When True, individuals who have exercised their CCPA right to opt out of sale/sharing of personal information are excluded from segment activation. Required for compliance with CCPA and its amendment CPRA. [Moved from audience_segment: CCPA opt-out handling is a compliance attribute specific to the CCPA regulatory obligation. This should be tracked in the segment-obligation compliance relationship where it can be audited, dated, and linked to the specific CCPA obligation record. The segment itself shouldnt carry obligation-specific compliance flags.] | Column ccpa_opt_out_honored (BOOLEAN) in audience.segment_regulatory_compliance',
    `compliance_status` STRING COMMENT 'Current compliance state of this segment with respect to this specific obligation. Values: compliant (segment meets all requirements), non_compliant (violations identified), under_review (audit in progress), remediation_in_progress (corrective actions underway), exempt (exemption granted). | Column compliance_status (STRING) in audience.segment_regulatory_compliance',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column created_at (TIMESTAMP) in audience.segment_regulatory_compliance',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance record was created in the system. | Column created_timestamp (TIMESTAMP) in audience.segment_regulatory_compliance',
    `deactivation_date` DATE COMMENT 'Date when this segment was deactivated or removed from use under this obligation. Null if segment remains active. Used to track compliance history. | Column deactivation_date (DATE) in audience.segment_regulatory_compliance',
    `deactivation_reason` STRING COMMENT 'Reason why the segment was deactivated under this obligation. Examples: compliance violation, obligation no longer applicable, segment retired, business decision. Null if segment is active. | Column deactivation_reason (STRING) in audience.segment_regulatory_compliance',
    `exemption_basis` STRING COMMENT 'Legal or regulatory basis for any exemption granted for this segment under this obligation. Null if no exemption applies. Examples: safe harbor provision, de minimis exception, grandfathered status, regulatory waiver reference. | Column exemption_basis (STRING) in audience.segment_regulatory_compliance',
    `exemption_expiration_date` DATE COMMENT 'Date when any granted exemption expires and full compliance is required. Null if no exemption or if exemption is permanent. | Column exemption_expiration_date (DATE) in audience.segment_regulatory_compliance',
    `gdpr_lawful_basis` STRING COMMENT 'The GDPR (General Data Protection Regulation) Article 6 lawful basis under which audience data is processed to build and activate this segment for EU audiences. consent requires explicit opt-in; legitimate_interest requires a balancing test; contract applies to subscriber-based segments; not_applicable for non-EU segments. Required for regulatory compliance reporting. [Moved from audience_segment: GDPR lawful basis is specific to the GDPR regulatory obligation and represents compliance metadata that belongs in the segment-obligation relationship. Different segments may have different lawful bases under GDPR, and this should be tracked as part of the compliance record with audit dates and status, not as a standalone attribute on the segment.] | Column gdpr_lawful_basis (STRING) in audience.segment_regulatory_compliance. Valid values are `consent|legitimate_interest|contract|not_applicable`',
    `is_coppa_restricted` BOOLEAN COMMENT 'Indicates whether this segment is subject to COPPA (Childrens Online Privacy Protection Act) restrictions, meaning it includes or may include children under 13. COPPA-restricted segments are prohibited from behavioral targeting and require parental consent mechanisms. Critical compliance flag for ad sales and digital activation workflows. [Moved from audience_segment: This boolean flag indicates COPPA applicability but doesnt capture the compliance relationship details. The segment_regulatory_compliance association should track the actual COPPA obligation (via regulatory_obligation_id) with full audit history, compliance status, and exemption basis. The flag in audience_segment can remain as a derived/cached indicator for quick filtering, but the authoritative compliance relationship lives in the association.] | Column is_coppa_restricted (BOOLEAN) in audience.segment_regulatory_compliance',
    `last_audit_date` DATE COMMENT 'Date when this segment-obligation pairing was last audited for compliance. Used to track audit frequency and schedule next review. | Column last_audit_date (DATE) in audience.segment_regulatory_compliance',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this compliance record was last modified. | Column last_updated_timestamp (TIMESTAMP) in audience.segment_regulatory_compliance',
    `next_audit_date` DATE COMMENT 'Scheduled date for the next compliance audit of this segment under this obligation. Calculated based on obligation compliance_frequency and risk_level. | Column next_audit_date (DATE) in audience.segment_regulatory_compliance',
    `remediation_due_date` DATE COMMENT 'Deadline by which remediation actions must be completed to avoid penalties or enforcement action. Null if no remediation required. | Column remediation_due_date (DATE) in audience.segment_regulatory_compliance',
    `remediation_plan` STRING COMMENT 'Description of corrective actions planned or in progress to address any compliance gaps. Null if segment is compliant or exempt. | Column remediation_plan (STRING) in audience.segment_regulatory_compliance',
    `responsible_compliance_officer` STRING COMMENT 'Name or employee ID of the compliance officer accountable for managing this segment-obligation compliance relationship. | Column responsible_compliance_officer (STRING) in audience.segment_regulatory_compliance',
    `risk_level` STRING COMMENT 'Assessed risk level specific to this segment-obligation combination. May differ from the obligations general risk_level based on segment characteristics (e.g., a childrens segment under COPPA has critical risk even if COPPAs general risk is high). | Column risk_level (STRING) in audience.segment_regulatory_compliance',
    `source_record_id` BIGINT COMMENT 'Medallion lineage column for _source_id | Column _source_id (STRING) in audience.segment_regulatory_compliance',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage tracking column for bronze->silver->gold tracing | Column updated_at (TIMESTAMP) in audience.segment_regulatory_compliance',
    CONSTRAINT pk_segment_regulatory_compliance PRIMARY KEY(`segment_regulatory_compliance_id`)
) COMMENT 'This association product represents the compliance relationship between audience segments and regulatory obligations. It captures the activation compliance status, audit history, and risk assessment for each segment-obligation pairing. Each record links one audience segment to one regulatory obligation with attributes that track when the segment was activated under that obligation, its current compliance state, audit findings, and any exemptions or special handling requirements.. Existence Justification: In media broadcasting operations, audience segments are subject to multiple regulatory obligations simultaneously (COPPA for childrens content, GDPR for EU audiences, accessibility requirements, advertising restrictions), and each regulatory obligation governs multiple audience segments across the portfolio. The compliance team actively manages these relationships by tracking activation dates, conducting periodic audits, assessing risk levels specific to each segment-obligation pairing, documenting exemptions, and maintaining remediation plans. This is an operational compliance management process, not an analytical correlation. | Unity Catalog table: media_broadcasting_ecm.audience.segment_regulatory_compliance Integrates with Adobe Experience Platform (audience platform).';

