    `clean_room_provider` STRING COMMENT 'Name of the clean room provider (e.g., LiveRamp, InfoSum, Habu)',
    `computed_at` TIMESTAMP COMMENT 'When the vector was computed',
    `confidence_score` DECIMAL(18,2) COMMENT 'Confidence score of the vector computation',
    `content_type_preferences` STRING COMMENT 'JSON map of content types to preference weights',
    `created_at` TIMESTAMP COMMENT 'Timestamp when the record was created',
    `embedding_model_name` STRING COMMENT 'Name of the ML model used to generate the embedding',
    `embedding_model_version` STRING COMMENT 'Version of the embedding model',
    `engagement_score` DECIMAL(18,2) COMMENT 'Overall engagement score based on viewing behavior',
    `feature_staleness_hours` STRING COMMENT 'Number of hours since last feature computation',
    `feature_vector_blob` STRING COMMENT 'Serialized feature vector data (JSON or binary encoded)',
    `feature_vector_dimension` STRING COMMENT 'Dimensionality of the feature vector',
    `feature_vector_type` STRING COMMENT 'Type of feature vector (e.g., embedding, topic, mood, behavioral)',
    `frequency_score` DECIMAL(18,2) COMMENT 'Score based on frequency of viewing sessions',
    `genre_affinity_scores` STRING COMMENT 'JSON map of genre IDs to affinity scores',
    `is_active` BOOLEAN COMMENT 'Whether this vector is currently active for recommendations',
    `is_active_flag` BOOLEAN COMMENT 'Indicates if this feature vector is currently active',
    `last_computed_timestamp` TIMESTAMP COMMENT 'Timestamp when the feature vector was last computed',
    `lookalike_segment_ids` STRING COMMENT 'JSON array of lookalike segment IDs this viewer matches',
    `model_version` STRING COMMENT 'ML model version that generated this vector',
    `monetary_value_score` DECIMAL(18,2) COMMENT 'Score based on subscriber monetary value',
    `privacy_consent_flag` BOOLEAN COMMENT 'Indicates if viewer has consented to personalization',
    `recency_score` DECIMAL(18,2) COMMENT 'Score based on recency of viewing activity',
    `source_event_count` BIGINT COMMENT 'Number of source events used to compute vector',
    `updated_at` TIMESTAMP COMMENT 'Timestamp when the record was last updated',
    `vector_dimension` BIGINT COMMENT 'Dimensionality of the feature vector',
    `vector_values` STRING COMMENT 'Serialized vector values (JSON array or binary)',
    `viewing_time_pattern` STRING COMMENT 'JSON representation of typical viewing time patterns',
    `valid_from` TIMESTAMP COMMENT 'Start of validity period',
    `valid_to` TIMESTAMP COMMENT 'End of validity period',
    CONSTRAINT pk_viewer_feature_vector PRIMARY KEY(`viewer_feature_vector_id`)
) COMMENT 'Feature vector representation of viewer preferences, behaviors, and attributes for recommendation engine input. Contains embeddings, topic affinities, mood preferences, and demographic signals derived from viewing history.';

